// Layer 2 core: find nearest depot city for any lat/lng
function _nearestDepot(lat, lng) {
  var minDist = Infinity;
  var nearest = null;
  Object.entries(CITY_CENTROIDS).forEach(function(e) {
    var name = e[0], coords = e[1];
    // Skip aliases (Albury, Wodonga, Tweed Heads etc — use only canonical names)
    if (['Albury','Wodonga','Tweed Heads','Maitland','Queanbeyan','Morwell','Bomaderry',
         'Boulder','Somerset','Shepparton-Mooroopna','Traralgon-Morwell','Nowra-Bomaderry',
         'Kalgoorlie-Boulder','Burnie-Somerset','Penrith','Parramatta','Liverpool',
         'Bundaberg'].indexOf(name) !== -1) return;
    var d = _haversineKm([lat,lng], coords);
    if (d < minDist) { minDist = d; nearest = name; }
  });
  return nearest ? { city: nearest, distKm: Math.round(minDist) } : null;
}

// Returns top N nearest depot cities to a given site city, sorted by distance.
// Each entry: { city, state, distKm, checked }
// Top 2 are pre-checked; rest unchecked.
var _DEPOT_ALIASES = ['Albury','Wodonga','Tweed Heads','Maitland','Queanbeyan','Morwell',
  'Bomaderry','Boulder','Somerset','Shepparton-Mooroopna','Traralgon-Morwell',
  'Nowra-Bomaderry','Kalgoorlie-Boulder','Burnie-Somerset','Penrith','Parramatta',
  'Liverpool','Bundaberg'];

// siteRef can be: a city name string, OR a [lat, lng] array for exact rural coordinates
function _topNearestDepots(siteRef, n) {
  n = n || 3;
  var siteCoord = Array.isArray(siteRef) ? siteRef : _getCityCentroid(siteRef);
  if (!siteCoord) return [];
  var ranked = [];
  Object.entries(CITY_CENTROIDS).forEach(function(e) {
    var name = e[0], coords = e[1];
    if (_DEPOT_ALIASES.indexOf(name) !== -1) return;
    var d = _roadDistKm(siteCoord, coords); // road distance estimate
    ranked.push({ city: name, state: _stateForDepot(name), distKm: d });
  });
  ranked.sort(function(a, b) { return a.distKm - b.distKm; });
  // All pre-ticked — customer must deselect
  return ranked.slice(0, n).map(function(r) {
    return { city: r.city, state: r.state, distKm: r.distKm, checked: true };
  });
}

// Master resolver: given a suburb string, return [city, state, isRural, nearestKm]
// isRural=true means it was matched via fallback (not exact suburb map)
function _resolveSuburbToCluster(suburbStr) {
  if (!suburbStr) return null;
  var q = suburbStr.toLowerCase().trim()
    .replace(/\s+(airport|aerodrome|station|mine|site|port|harbour|harbor|base|camp|depot|wharf|terminal|industrial estate|industrial park|business park|industrial area|rd|road|st|street|ave|avenue|hwy|highway|way|dr|drive|pl|place|ct|court|cres|crescent|blvd|boulevard|loop|track|close|circuit)$/i, '')
    .trim();

  // Normalise common misspellings / phonetic variants
  var qNorm = q
    .replace(/headl/g, 'hedl')         // port headland → port hedland
    .replace(/hedland/g, 'hedland')    // ensure hedland stays
    .replace(/kalgoorly/g, 'kalgoorlie')
    .replace(/kalgoorie/g, 'kalgoorlie')
    .replace(/townsvill$/g, 'townsville')
    .replace(/brisban$/g, 'brisbane')
    .replace(/melbourn$/g, 'melbourne')
    .replace(/sydny/g, 'sydney')
    .replace(/canberrra/g, 'canberra')
    .replace(/geraldton/g, 'geraldton')
    .replace(/karratha/g, 'karratha')
    .replace(/rockhampt/g, 'rockhampton')
    .replace(/toowoomba/g, 'toowoomba')
    .replace(/wollongon$/g, 'wollongong');

  // Build list of queries to try in order
  var queries = q === qNorm ? [q] : [q, qNorm];

  for (var _qi = 0; _qi < queries.length; _qi++) {
    var _q = queries[_qi];

  // 1. Check AU_SUBURB_CITY (exact match)
  if (AU_SUBURB_CITY[_q]) {
    return { city: AU_SUBURB_CITY[_q][0], state: AU_SUBURB_CITY[_q][1], isRural: false, nearestKm: 0 };
  }

  // 2. Prefix match in AU_SUBURB_CITY (suburb starts with q, OR q starts with a suburb name)
  var prefixKey = Object.keys(AU_SUBURB_CITY).find(function(k) {
    return k.startsWith(_q) || (_q.startsWith(k) && k.length >= 4);
  });
  if (prefixKey) {
    return { city: AU_SUBURB_CITY[prefixKey][0], state: AU_SUBURB_CITY[prefixKey][1], isRural: false, nearestKm: 0 };
  }

  // 3. Check RURAL_DEPOT_MAP — exact, prefix, or q contains/starts with key
  if (RURAL_DEPOT_MAP[_q]) {
    return { city: RURAL_DEPOT_MAP[_q][0], state: RURAL_DEPOT_MAP[_q][1], isRural: true, nearestKm: null };
  }
  var ruralKey = Object.keys(RURAL_DEPOT_MAP).find(function(k) {
    return k.startsWith(_q) || (_q.startsWith(k) && k.length >= 4) || _q === k;
  });
  if (ruralKey) {
    return { city: RURAL_DEPOT_MAP[ruralKey][0], state: RURAL_DEPOT_MAP[ruralKey][1], isRural: true, nearestKm: null };
  }

  // 4. Check RURAL_COORDS → nearest depot by Haversine
  var coordKey = Object.keys(RURAL_COORDS).find(function(k) {
    return k.startsWith(_q) || _q.startsWith(k) || k === _q;
  });
  if (coordKey) {
    var coords = RURAL_COORDS[coordKey];
    var nearest = _nearestDepot(coords[0], coords[1]);
    if (nearest) {
      var st = _stateForDepot(nearest.city);
      return { city: nearest.city, state: st, isRural: true, nearestKm: nearest.distKm };
    }
  }

  } // end queries loop

  return null;
}

// Helper: infer state for a depot city name
function _stateForDepot(city) {
  var stateMap = {
    'Melbourne':'VIC','Geelong':'VIC','Ballarat':'VIC','Bendigo':'VIC',
    'Shepparton':'VIC','Traralgon':'VIC','Warrnambool':'VIC',
    'Sydney':'NSW','Newcastle':'NSW','Central Coast':'NSW','Wollongong':'NSW',
    'Albury-Wodonga':'NSW','Wagga Wagga':'NSW','Tamworth':'NSW','Orange':'NSW',
    'Dubbo':'NSW','Nowra':'NSW','Bathurst':'NSW','Coffs Harbour':'NSW',
    'Brisbane':'QLD','Gold Coast':'QLD','Sunshine Coast':'QLD','Toowoomba':'QLD',
    'Townsville':'QLD','Cairns':'QLD','Rockhampton':'QLD','Hervey Bay':'QLD','Mackay':'QLD',
    'Perth':'WA','Bunbury':'WA','Geraldton':'WA','Kalgoorlie':'WA','Busselton':'WA',
    'Adelaide':'SA','Canberra':'ACT',
    'Hobart':'TAS','Launceston':'TAS','Devonport':'TAS','Burnie':'TAS',
    'Darwin':'NT',
  };
  return stateMap[city] || '';
}

function detectCityFromAddress(address) {
  if (!address) return null;
  const lower = address.toLowerCase().replace(/[,\.]/g,' ').replace(/\s+/g,' ').trim();
  const words = lower.split(' ');
  for (let len = 3; len >= 1; len--) {
    for (let i = 0; i <= words.length - len; i++) {
      const phrase = words.slice(i, i+len).join(' ');
      if (AU_SUBURB_CITY[phrase]) return AU_SUBURB_CITY[phrase];
    }
  }
  return null;
}

function updateCityFromAddress(val) {
  const pill = document.getElementById('sqm-city-pill');
  const cityName = document.getElementById('sqm-city-name');
  const cityState = document.getElementById('sqm-city-state');
  const result = detectCityFromAddress(val);
  if (result) {
    if (cityName) cityName.textContent = result[0];
    if (cityState) cityState.textContent = result[1];
    if (pill) pill.style.display = 'inline-flex';
  } else {
    if (pill) pill.style.display = 'none';
  }
}

// ── Registration suburb autocomplete ────────────────────────
var _regSuburbDebounce = null;
function regSuburbInput(val) {
  clearTimeout(_regSuburbDebounce);
  const drop = document.getElementById('sqm-reg-suburb-drop');
  const cityEl  = document.getElementById('sqm-reg-city');
  const stateEl = document.getElementById('sqm-reg-state');
  // Clear until user picks from dropdown (handles ambiguous suburbs)
  if (cityEl)  cityEl.value  = '';
  if (stateEl) stateEl.value = '';
  _regSuburbDebounce = setTimeout(() => {
    if (!val || val.length < 2) { if(drop) drop.style.display='none'; return; }
    const matches = _suburbMatches(val.toLowerCase().trim());
    if (matches.length === 0) { if(drop) drop.style.display='none'; return; }
    // Auto-fill if only one option
    if (matches.length === 1) {
      if (cityEl)  cityEl.value  = matches[0].city;
      if (stateEl) stateEl.value = matches[0].state;
      _regAssembleAddress();
    }
    if (drop) {
      drop.innerHTML = matches.map(m => {
        const display = m.suburb.split(' ').map(w=>w.charAt(0).toUpperCase()+w.slice(1)).join(' ');
        return `<div onclick="regSuburbSelect('${m.suburb}','${display}','${m.city}','${m.state}')"
          style="padding:.55rem .9rem;cursor:pointer;font-size:.88rem;border-bottom:1px solid #F1F5F9"
          onmouseover="this.style.background='#EFF6FF'" onmouseout="this.style.background=''"
          ><strong>${display}</strong> <span style="color:#64748B;font-size:.8rem">${m.city}, ${m.state}</span></div>`;
      }).join('');
      drop.style.display = 'block';
    }
  }, 150);
}

function regSuburbSelect(key, display, city, state) {
  const inp   = document.getElementById('sqm-reg-suburb');
  const cityEl  = document.getElementById('sqm-reg-city');
  const stateEl = document.getElementById('sqm-reg-state');
  const drop  = document.getElementById('sqm-reg-suburb-drop');
  if (inp)    inp.value   = display;
  if (cityEl) cityEl.value  = city;
  if (stateEl) stateEl.value = state;
  if (drop)   if (drop) if (drop) drop.style.display = 'none';
  _regAssembleAddress();
}

function _regAssembleAddress() {
  const street = (document.getElementById('sqm-reg-street')?.value || '').trim();
  const suburb = (document.getElementById('sqm-reg-suburb')?.value || '').trim();
  const city   = (document.getElementById('sqm-reg-city')?.value   || '').trim();
  const state  = (document.getElementById('sqm-reg-state')?.value  || '').trim();
  const parts  = [street, suburb, state].filter(Boolean);
  const hidden = document.getElementById('sqm-reg-address');
  if (hidden) hidden.value = parts.join(', ');
}

// Close registration suburb dropdown on outside click
document.addEventListener('click', e => {
  const drop = document.getElementById('sqm-reg-suburb-drop');
  const inp  = document.getElementById('sqm-reg-suburb');
  if (drop && inp && !inp.contains(e.target) && !drop.contains(e.target)) {
    drop.style.display = 'none';
  }
});

function formatABN(input) {
  let v = input.value.replace(/\D/g,'').slice(0,11);
  if (v.length > 2) v = v.slice(0,2)+' '+v.slice(2);
  if (v.length > 6) v = v.slice(0,6)+' '+v.slice(6);
  if (v.length > 10) v = v.slice(0,10)+' '+v.slice(10);
  input.value = v;
}
function formatACN(input) {
  let v = input.value.replace(/\D/g,'').slice(0,9);
  if (v.length > 3) v = v.slice(0,3)+' '+v.slice(3);
  if (v.length > 7) v = v.slice(0,7)+' '+v.slice(7);
  input.value = v;
}

// Session-registered business (persists until page reload)
var _sessionRegisteredOrg = null;
function getEffectiveOrg() {
  if (_sessionRegisteredOrg) return _sessionRegisteredOrg;
  if (currentUser) {
    // 1. Check hardcoded org registry first
    const hardcoded = getCustomerOrg(currentUser.email);
    if (hardcoded) return hardcoded;

    // 2. For rental/staff/manager/admin: build from RENTAL_COMPANIES + localStorage
    if (['rental','staff','manager','admin'].includes(currentUser.role)) {
      const rc = RENTAL_COMPANIES.find(c => c.email && c.email.toLowerCase() === currentUser.email.toLowerCase());
      const company = loadAccountField(currentUser.email, 'company') || (rc ? rc.name : '') || 'Noyo Pty Ltd';
      const abn     = loadAccountField(currentUser.email, 'abn')     || '';
      const address = loadAccountField(currentUser.email, 'address') || (rc ? rc.address : '') || '';
      const suburb  = loadAccountField(currentUser.email, 'suburb')  || '';
      const city    = loadAccountField(currentUser.email, 'city')    || (rc ? rc.baseCity : '') || '';
      const state   = loadAccountField(currentUser.email, 'state')   || '';
      const phone   = loadAccountField(currentUser.email, 'mobile')  || (rc ? rc.phone : '')   || '';
      const radius  = loadAccountField(currentUser.email, 'serviceRadiusKm') || String(rc ? rc.serviceRadiusKm : 75);
      if (company) {
        return {
          company, abn, address, suburb, city, state,
          phone, serviceRadiusKm: parseInt(radius, 10) || 75,
          fromStorage: true, isRental: true
        };
      }
    }

    // 3. Fall back to localStorage-registered customer org (any role)
    const company = loadAccountField(currentUser.email, 'company');
    if (company) {
      return {
        company,
        address: loadAccountField(currentUser.email, 'address') || '',
        abn:     loadAccountField(currentUser.email, 'abn')     || '',
        phone:   loadAccountField(currentUser.email, 'mobile')  || '',
        suburb:  loadAccountField(currentUser.email, 'suburb')  || '',
        city:    loadAccountField(currentUser.email, 'city')    || '',
        state:   loadAccountField(currentUser.email, 'state')   || '',
        fromStorage: true
      };
    }
  }
  return null;
}

function openSendQuotesModal() {
  if (quoteCart.length === 0) {
    showToast('Add at least 1 machine to your cart first','#EF4444');
    return;
  }
  const ref = generateQuoteRef();
  { const _el_sqm_ref_badge = document.getElementById('sqm-ref-badge'); if (_el_sqm_ref_badge) _el_sqm_ref_badge.textContent = ref; }
  { const _el_sqm_ref_status = document.getElementById('sqm-ref-status'); if (_el_sqm_ref_status) _el_sqm_ref_status.textContent = '🕐 Draft'; }
  document.getElementById('send-quotes-modal').dataset.ref = ref;
  const org = getEffectiveOrg();
  if (org) {
    { const _e=document.getElementById('sqm-reg-step'); if(_e) _e.style.display='none'; }
    { const _e=document.getElementById('sqm-enquiry-step'); if(_e) _e.style.display='block'; }
    populateSqmMachineList();
    document.getElementById('sqm-org-name').textContent    = org.company;
    document.getElementById('sqm-org-abn').textContent     = org.abn ? 'ABN ' + org.abn : '';
    { const _el_sqm_org_address = document.getElementById('sqm-org-address'); if (_el_sqm_org_address) _el_sqm_org_address.textContent = org.address; }
    // Pre-fill service radius from org data for rental users
    if (org.serviceRadiusKm) {
      const radEl = document.getElementById('sqm-radius');
      if (radEl) radEl.value = String(org.serviceRadiusKm);
    }
    if (currentUser) {
      document.getElementById('sqm-name').value  = currentUser.name || '';
      document.getElementById('sqm-email').value = currentUser.email || '';
      const storedMobile = loadAccountField(currentUser.email, 'mobile');
      const mobileEl = document.getElementById('sqm-mobile');
      const mobileNote = document.getElementById('sqm-mobile-label-note');
      if (storedMobile) {
        if (mobileEl) {
          mobileEl.value = storedMobile;
          mobileEl.readOnly = true;
          mobileEl.style.background = '#F8FAFC';
          mobileEl.style.cursor = 'default';
        }
        if (mobileNote) mobileNote.textContent = '(auto-filled)';
      } else {
        if (mobileEl) {
          mobileEl.value = org.phone || '';
          mobileEl.readOnly = false;
          mobileEl.style.background = '#fff';
          mobileEl.style.cursor = '';
        }
        if (mobileNote) mobileNote.textContent = org.phone ? '(from registration)' : '← please enter';
      }
    } else {
      document.getElementById('sqm-name').value  = '';
      const mobileEl = document.getElementById('sqm-mobile');
      if (mobileEl) {
        mobileEl.value = '';
        mobileEl.readOnly = false;
        mobileEl.style.background = '#fff';
      }
    }
    document.getElementById('sqm-site-address').value = '';
    document.getElementById('sqm-notes').value         = '';
    document.getElementById('sqm-date').value          = new Date().toISOString().split('T')[0];
    resetSuburbVerification();
  } else {
    { const _e=document.getElementById('sqm-reg-step'); if(_e) _e.style.display='block'; }
    { const _e=document.getElementById('sqm-enquiry-step'); if(_e) _e.style.display='none'; }
    // ALWAYS clear all registration fields — never pre-fill from a previous registration
    ['sqm-reg-company','sqm-reg-abn','sqm-reg-phone','sqm-reg-acn','sqm-reg-street','sqm-reg-suburb','sqm-reg-city','sqm-reg-state'].forEach(id=>{
      const el = document.getElementById(id); if(el) el.value='';
    });
    const hidden = document.getElementById('sqm-reg-address'); if(hidden) hidden.value='';
    const drop = document.getElementById('sqm-reg-suburb-drop'); if(drop) drop.style.display='none';
    const radEl = document.getElementById('sqm-reg-radius'); if(radEl) radEl.value='75';
    // Reset sector checkboxes
    document.querySelectorAll('input[name="sqm-sector"]').forEach(cb => { cb.checked = false; });
  }
  document.getElementById('send-quotes-modal').classList.add('open');
  const sidebar = document.getElementById('cart-sidebar');
  if (sidebar && sidebar.classList.contains('open')) toggleCart();
  // Attach Google Places if ready
  setTimeout(_attachSuburbAutocomplete, 200);
}

function populateSqmMachineList() {
  const container = document.getElementById('sqm-machine-list');
  const badge = document.getElementById('sqm-machine-count-badge');
  if (badge) badge.textContent = quoteCart.length;
  const curCount = quoteCart.length;

  container.innerHTML = `
    <div style="background:#EFF6FF;border:1.5px solid #BFDBFE;border-radius:10px;padding:.6rem 1rem;margin-bottom:.9rem;display:flex;align-items:center;gap:.5rem">
      <span style="font-size:1.1rem">🛒</span>
      <span style="font-weight:800;color:#1D4ED8;font-size:.95rem">${curCount} machine${curCount !== 1 ? 's' : ''} in your cart</span>
      <span style="color:#64748B;font-size:.8rem;margin-left:.3rem">— all will be quoted together</span>
    </div>
  ` + quoteCart.map((m,i) => {
    const jr = m.jobRequirements || {};
    const specs = [
      jr.loadWeightKg  && `⚖️ ${jr.loadWeightKg} kg`,
      jr.liftHeightM   && `📏 ${jr.liftHeightM}m lift`,
      jr.forwardReachM && `↔️ ${jr.forwardReachM}m reach`,
      jr.terrain      && `⛰️ ${jr.terrain}`,
    ].filter(Boolean).join(' · ');
    const attHtml = jr.attachmentsRequired
      ? `<div style="margin-top:.3rem;font-size:.78rem;color:#1E40AF"><span style="font-weight:700">🔩</span> ${jr.attachmentsRequired}</div>`
      : '';
    const kymdTynes = (m.tynes && m.tynes.length)
      ? `<div style="margin-top:.25rem;display:flex;flex-wrap:wrap;gap:.25rem">${m.tynes.map(t=>`<span style="background:#EFF6FF;border:1px solid #BFDBFE;border-radius:5px;padding:.1rem .4rem;font-size:.73rem;font-weight:700;color:#1D4ED8">🔱 Tyne: ${t}</span>`).join('')}</div>`
      : '';
    const kymdAtt = (m.attachments && m.attachments.length)
      ? `<div style="margin-top:.2rem;display:flex;flex-wrap:wrap;gap:.25rem">${m.attachments.map(a=>`<span style="background:#F0FDF4;border:1px solid #86EFAC;border-radius:5px;padding:.1rem .4rem;font-size:.73rem;font-weight:700;color:#15803D">🔧 ${a}</span>`).join('')}</div>`
      : '';
    const curDur = m.duration || '1-day';
    const durOpts = ['half-day|Half day','1-day|1 day','1-week|1 week','2-weeks|2 weeks','1-month|1 month','3-months|3 months','6-months|6 months','12-months-plus|12+ months']
      .map(o=>{const[v,l]=o.split('|');return `<option value="${v}"${curDur===v?' selected':''}>${l}</option>`;}).join('');
    return `<div class="sqm-machine-item-wrap">
      <div class="sqm-machine-top">
        <span style="font-size:1.4rem">${m.emoji}</span>
        <div style="flex:1;min-width:0">
          <strong style="color:#1E40AF">${m.name||m.id||'Unknown machine'}</strong>${m.quantity && m.quantity > 1 ? `<span style="margin-left:.4rem;background:#DBEAFE;color:#1D4ED8;font-size:.72rem;font-weight:900;padding:.1rem .45rem;border-radius:20px">×${m.quantity}</span>` : ''}
          ${specs ? `<div style="font-size:.75rem;color:#475569;margin-top:.15rem">${specs}</div>` : ''}
          ${attHtml}${kymdTynes}${kymdAtt}
        </div>
      </div>
      <div class="sqm-machine-dur" style="display:flex;align-items:center;gap:.7rem;flex-wrap:wrap">
        <div style="display:flex;align-items:center;gap:.4rem;flex:0 0 auto">
          <label style="font-size:.82rem;font-weight:700;color:#334155">Qty <span style="color:#EF4444">*</span></label>
          <input type="number" min="1" step="1" id="sqm-qty-${i}"
            value="${quoteCart[i].quantity||1}"
            oninput="quoteCart[${i}].quantity=Math.max(1,parseInt(this.value)||1);this.value=quoteCart[${i}].quantity;this.style.borderColor=quoteCart[${i}].quantity>0?'#94A3B8':'#EF4444'"
            style="width:60px;padding:.35rem .5rem;border:1.5px solid #94A3B8;border-radius:8px;font-size:.9rem;font-weight:800;text-align:center;color:#0F172A;font-family:'Nunito',sans-serif">
        </div>
        <div style="display:flex;align-items:center;gap:.4rem;flex:1;min-width:160px">
          <label style="font-size:.82rem;font-weight:700;color:#334155">Hire duration:</label>
          <select class="sqm-dur-select" id="sqm-dur-${i}" onchange="quoteCart[${i}].duration=this.value" style="flex:1">${durOpts}</select>
        </div>
      </div>
    </div>`;
  }).join('');
}

function buildMachineListHtml() {
  return quoteCart.map(m => {
    const jr = m.jobRequirements || {};
    const specs = [
      jr.loadWeightKg  && `⚖️ ${jr.loadWeightKg} kg`,
      jr.liftHeightM   && `📏 ${jr.liftHeightM}m lift`,
      jr.forwardReachM && `↔️ ${jr.forwardReachM}m reach`,
      jr.terrain      && `⛰️ ${jr.terrain}`,
    ].filter(Boolean).join('  ·  ');
    const attHtml = jr.attachmentsRequired
      ? `<div style="margin-top:.3rem;font-size:.78rem;color:#1E40AF"><span style="font-weight:700">🔩 Attachments:</span> ${jr.attachmentsRequired}</div>`
      : '';
    return `<div class="sqm-machine-item">
      <span class="sqm-emoji">${m.emoji}</span>
      <div style="flex:1;min-width:0"><strong>${m.name}</strong>
        ${specs ? `<div style="font-size:.75rem;color:#475569;margin-top:.1rem">${specs}</div>` : ''}
        ${attHtml}
      </div>
    </div>`;
  }).join('');
}

function submitRegistration() {
  const company = document.getElementById('sqm-reg-company').value.trim();
  const abn     = document.getElementById('sqm-reg-abn').value.trim();
  // Assemble address from parts
  _regAssembleAddress();
  const street  = document.getElementById('sqm-reg-street')?.value.trim() || '';
  const suburb  = document.getElementById('sqm-reg-suburb')?.value.trim() || '';
  const state   = document.getElementById('sqm-reg-state')?.value.trim()  || '';
  const address = document.getElementById('sqm-reg-address').value.trim();
  if (!company) { showToast('Please enter your company name','#EF4444'); return; }
  if (!abn || abn.replace(/\s/g,'').length < 11) { showToast('Please enter a valid 11-digit ABN','#EF4444'); return; }
  if (!street)  { showToast('Please enter your street address','#EF4444'); return; }
  if (!suburb)  { showToast('Please enter your suburb','#EF4444'); document.getElementById('sqm-reg-suburb')?.focus(); return; }
  const phone = document.getElementById('sqm-reg-phone').value.trim();
  if (!phone) {
    { const _e=document.getElementById('sqm-reg-phone'); if(_e) _e.style.borderColor='#EF4444'; }
    showToast('Please enter a mobile number','#EF4444'); return;
  }
  const serviceRadiusKm = parseInt(document.getElementById('sqm-reg-radius')?.value || '75', 10);
  const baseCity = (document.getElementById('sqm-reg-city')?.value || '').trim();
  _sessionRegisteredOrg = {
    company, abn, address,
    phone,
    baseCity,
    serviceRadiusKm,
    acn:      document.getElementById('sqm-reg-acn').value.trim(),
    bizType:  document.getElementById('sqm-reg-type').value,
    industry: document.getElementById('sqm-reg-industry').value,
    sectors:  [...document.querySelectorAll('input[name="sqm-sector"]:checked')].map(cb => cb.value),
    session:  true
  };
  // Register in RENTAL_COMPANIES so routing works immediately in this session
  const existingIdx = RENTAL_COMPANIES.findIndex(c => c.name === company);
  const rcEntry = {
    id: 'rc-session-' + Date.now(),
    name: company, email: currentUser?.email || '',
    phone, address, baseCity, serviceRadiusKm,
    cities: [baseCity],
    machines: (_sessionRegisteredOrg.sectors||[]).join(', '),
    sectors: _sessionRegisteredOrg.sectors,
    active: true
  };
  if (existingIdx > -1) {
    RENTAL_COMPANIES[existingIdx] = { ...RENTAL_COMPANIES[existingIdx], ...rcEntry };
  } else {
    RENTAL_COMPANIES.push(rcEntry);
  }
  { const _e=document.getElementById('sqm-reg-step'); if(_e) _e.style.display='none'; }
  { const _e=document.getElementById('sqm-enquiry-step'); if(_e) _e.style.display='block'; }
  populateSqmMachineList();
  document.getElementById('sqm-org-name').textContent    = _sessionRegisteredOrg.company;
  document.getElementById('sqm-org-abn').textContent     = 'ABN ' + _sessionRegisteredOrg.abn;
  { const _el_sqm_org_address = document.getElementById('sqm-org-address'); if (_el_sqm_org_address) _el_sqm_org_address.textContent = _sessionRegisteredOrg.address; }
  if (currentUser) document.getElementById('sqm-name').value  = currentUser.name || '';
  if (currentUser) document.getElementById('sqm-email').value = currentUser.email || '';
  document.getElementById('sqm-site-address').value = '';
  document.getElementById('sqm-mobile').value        = '';
  document.getElementById('sqm-notes').value         = '';
  document.getElementById('sqm-date').value          = '';
  resetSuburbVerification();
  setTimeout(_attachSuburbAutocomplete, 200);
  showToast('Business registered for this session!', '#16A34A');
}

