// ── Result page disclaimer ────────────────────────────────────
function resultDisclaimerToggle() {
  const chk = document.getElementById('result-disclaimer-check');
  const btn = document.getElementById('result-cart-btn');
  if (!btn) return;
  if (chk && chk.checked) {
    btn.disabled = false;
    btn.style.background = 'var(--accent)';
    btn.style.cursor = 'pointer';
    btn.style.boxShadow = '0 4px 16px rgba(255,107,53,.35)';
    btn.style.transform = '';
  } else {
    btn.disabled = true;
    btn.style.background = '#94A3B8';
    btn.style.cursor = 'not-allowed';
    btn.style.boxShadow = 'none';
  }
}

function resultCartClick() {
  const chk = document.getElementById('result-disclaimer-check');
  if (!chk || !chk.checked) return; // safety guard
  toggleCart();
}

function showResultDisclaimer() {
  // Show disclaimer block and reset its state
  const wrap = document.getElementById('result-disclaimer-wrap');
  if (!wrap) return; // not on results page, skip safely
  wrap.style.display = 'block';
  const chk = document.getElementById('result-disclaimer-check');
  if (chk) chk.checked = false;
  const btn = document.getElementById('result-cart-btn');
  if (btn) {
    btn.disabled = true;
    btn.style.background = '#94A3B8';
    btn.style.cursor = 'not-allowed';
    btn.style.boxShadow = 'none';
  }
}

