function kymSearch2() {
  const input = document.getElementById('kym-search-input2');
  const rawQuery = input ? input.value.trim().toLowerCase() : '';
  const {corrected, changed, original} = _correctQuery(rawQuery);
  _kymQuery = corrected;
  _kymDidYouMeanQuery = changed ? {original, corrected} : null;
  if (_kymQuery) {
    _kymCat = '';
    document.querySelectorAll('.kym-chip').forEach(c => c.classList.remove('active'));
    document.querySelectorAll('.kym-chip:first-child').forEach(c => c.classList.add('active'));
  }
  kymRender();
}

function kymSetBrand(brand) {
  _kymBrand = (_kymBrand === brand) ? '' : brand; // toggle
  kymRender();
}

function kymSetCat2(cat, btn) {
  _kymCat = cat;
  _kymBrand = ''; // reset brand filter on category switch
  document.querySelectorAll('.kym-chip').forEach(c => c.classList.remove('active'));
  if (btn) btn.classList.add('active');
  kymRender();
}

function kymSetCat(cat, btn) {
  _kymCat = cat;
  _kymBrand = ''; // reset brand filter on category switch
  document.querySelectorAll('.kym-chip').forEach(c => c.classList.remove('active'));
  if (btn) btn.classList.add('active');
  kymRender();
}

// ── Fuzzy search / "Did you mean?" system ────────────────────────────────────
// Levenshtein distance between two strings
function _levenshtein(a, b) {
  if (a === b) return 0;
  if (!a.length) return b.length;
  if (!b.length) return a.length;
  const dp = Array.from({length: b.length + 1}, (_, i) => i);
  for (let i = 0; i < a.length; i++) {
    let prev = i + 1;
    for (let j = 0; j < b.length; j++) {
      const val = a[i] === b[j] ? dp[j] : Math.min(dp[j] + 1, prev + 1, dp[j + 1] + 1);
      dp[j] = prev;
      prev = val;
    }
    dp[b.length] = prev;
  }
  return dp[b.length];
}

// Master dictionary — all known good search terms
// Built from synonym keys + common machine spec words
const _KYM_DICTIONARY = (() => {
  const words = new Set();
  // From synonym map keys
  const synKeys = [
    'telehandler','telehandlers','tele','rotating','rotational','rotary','rotation',
    'reach','reach truck','reach trucks','reach stacker','reach stackers',
    'high reach','high mast','high lift','high bay','extended mast',
    'forklift','forklifts','fork','counterbalance','order picker','order pickers',
    'picking truck','narrow aisle','walkie stacker','pedestrian stacker',
    'scissor','scissor lift','scissor lifts','boom','boom lift','boom lifts',
    'cherry picker','cherry pickers','articulating','telescopic',
    'material lift','material lifts','material hoist','duct lift',
    'push around','push-around','personnel lift','vertical mast','manlift',
    'pallet jack','pallet truck','pallet mover','rider pallet',
    'electric','diesel','lpg','petrol','battery','lithium',
    'rough terrain','indoor','outdoor','compact',
    'manitou','jcb','magni','merlo','dieci','toyota','linde','crown','hyster','still',
    'jungheinrich','heli','liugong','hangcha','enforcer','noblelift','magni',
    'sinoboom','genie','skyjack','haulotte','snorkel','lgmg','xcmg','monitor access','niftylift',
    'mrt','mrtx','rth','roto','eth','pegasus',
    'crane replacement','man basket','work platform','jib','hook',
    'warehouse','racking','construction','agriculture','industrial',
    'precast','concrete','steel','heavy duty','compact',
    'man lift','scissor lift','boom lift','pallet jack',
  ];
  synKeys.forEach(k => k.split(' ').forEach(w => { if (w.length > 2) words.add(w); }));
  // Spec value words
  ['1t','1.5t','2t','2.5t','3t','3.5t','4t','4.5t','5t','6t','7t','8t','9t','10t',
   '12m','15m','16m','18m','20m','21m','22m','24m','25m','26m','27m','28m','30m','35m','40m',
   '4wd','2wd','stage','electric','battery','diesel','lpg','petrol',
  ].forEach(w => words.add(w));
  return [...words];
})();

// Correct a single word — returns best match if edit distance ≤ threshold
function _correctWord(word) {
  if (word.length <= 2) return word; // too short to correct
  const threshold = word.length <= 5 ? 1 : word.length <= 8 ? 2 : 3;
  let best = null, bestDist = Infinity;
  for (const candidate of _KYM_DICTIONARY) {
    if (Math.abs(candidate.length - word.length) > threshold) continue;
    const d = _levenshtein(word, candidate);
    if (d < bestDist && d <= threshold) {
      bestDist = d;
      best = candidate;
    }
  }
  return best || word;
}

// Correct a full multi-word query
// Returns {corrected: string, changed: boolean, original: string}
function _correctQuery(query) {
  if (!query || !query.trim()) return {corrected: query, changed: false, original: query};
  const original = query.trim().toLowerCase();

  // First try multi-word synonym correction (e.g. "high recah" → "high reach")
  // Check all known multi-word synonyms for fuzzy match
  const allSyns = Object.keys(KYM_CAT_SYNONYMS || {});
  let bestSynMatch = null, bestSynDist = Infinity;
  for (const syn of allSyns) {
    if (Math.abs(syn.length - original.length) > Math.ceil(original.length * 0.35)) continue;
    const d = _levenshtein(original, syn);
    const maxAllowed = Math.ceil(syn.length * 0.25); // allow 25% character errors
    if (d < bestSynDist && d <= maxAllowed && d > 0) {
      bestSynDist = d;
      bestSynMatch = syn;
    }
  }
  if (bestSynMatch) {
    return {corrected: bestSynMatch, changed: true, original};
  }

  // Word-by-word correction for multi-word queries
  const words = original.split(/\s+/);
  const correctedWords = words.map(w => _correctWord(w));
  const corrected = correctedWords.join(' ');
  const changed = corrected !== original;
  return {corrected, changed, original};
}

var _kymDidYouMeanQuery = null; // tracks what was auto-corrected

function kymSearch() {
  const input = document.getElementById('kym-search-input');
  const rawQuery = input ? input.value.trim().toLowerCase() : '';

  // Run spell correction
  const {corrected, changed, original} = _correctQuery(rawQuery);
  _kymQuery = corrected;
  _kymDidYouMeanQuery = changed ? {original, corrected} : null;

  // Reset cat to all if there's a text query so search crosses categories
  if (_kymQuery) {
    _kymCat = '';
    document.querySelectorAll('.kym-chip').forEach(c => c.classList.remove('active'));
    const allChip = document.querySelector('.kym-chip');
    if (allChip) allChip.classList.add('active');
  }
  kymRender();
}

