                  const rOrig = req.responses[r._origIdx !== undefined ? r._origIdx : si];
                  const isAcc2 = rOrig && rOrig.accepted === true;
                  const isRej2 = rOrig && (rOrig.rejected === true || rOrig.autoRejected === true);
                  const tReq3 = (req.machines||[]).length;
