function renderRentalCompanies(filterCity) {
  const grid = document.getElementById('rc-company-grid');
  if (!grid) return;
  const cos = filterCity && filterCity !== 'all'
    ? RENTAL_COMPANIES.filter(c => (c.cities||[]).map(x=>x.toLowerCase()).includes(filterCity.toLowerCase()))
    : RENTAL_COMPANIES;

  // Build city chip bar
  const allCities = [...new Set(RENTAL_COMPANIES.flatMap(c => c.cities||[]))].sort();
  const chipsDiv = document.getElementById('rc-city-chips');
  if (chipsDiv) {
    if (chipsDiv) chipsDiv.innerHTML = `<button class="fchip ${!filterCity||filterCity==='all'?'active':''}" onclick="filterRentalCos('all',this)">All</button>`
      + allCities.map(city => `<button class="fchip ${filterCity===city?'active':''}" onclick="filterRentalCos('${city}',this)">${city}</button>`).join('');
  }

  if (cos.length === 0) {
    grid.innerHTML = '<div style="padding:2rem;color:#94A3B8;text-align:center">No rental companies found for this city.</div>';
    return;
  }

  grid.innerHTML = cos.map(c => `
    <div style="background:#fff;border:1.5px solid #E2E8F0;border-radius:14px;padding:1.1rem 1.2rem;position:relative">
      <div style="display:flex;align-items:flex-start;justify-content:space-between;gap:.5rem;margin-bottom:.6rem">
        <div>
          <div style="font-weight:800;font-size:1rem;color:#0F172A">${c.name}</div>
          <div style="font-size:.8rem;color:#64748B;margin-top:.1rem">${c.address}</div>
        </div>
        <span style="background:${c.active?'#F0FDF4':'#F1F5F9'};color:${c.active?'#16A34A':'#94A3B8'};
          border:1px solid ${c.active?'#86EFAC':'#E2E8F0'};border-radius:20px;font-size:.72rem;font-weight:800;
          padding:.15rem .6rem;white-space:nowrap;flex-shrink:0">${c.active?'Active':'Inactive'}</span>
      </div>
      <div style="display:flex;gap:.4rem;flex-wrap:wrap;margin-bottom:.65rem">
        <span style="background:#EFF6FF;color:#1D4ED8;border:1px solid #BFDBFE;border-radius:20px;padding:.15rem .55rem;font-size:.75rem;font-weight:700">📍 ${c.baseCity || (c.cities&&c.cities[0]) || '—'}</span>
        <span style="background:#FEF9C3;color:#78350F;border:1px solid #FDE68A;border-radius:20px;padding:.15rem .55rem;font-size:.75rem;font-weight:700">📡 ${c.serviceRadiusKm || 75} km radius</span>
      </div>
      <div style="font-size:.8rem;color:#64748B;margin-bottom:.5rem">🏗️ ${c.machines}</div>
      <div style="display:flex;gap:.5rem;align-items:center;font-size:.82rem">
        <span>📧 ${c.email}</span>
        ${c.phone ? `<span style="color:#94A3B8">·</span><span>📞 ${c.phone}</span>` : ''}
      </div>
      <div style="display:flex;gap:.5rem;margin-top:.8rem">
        <button onclick="editCompany('${c.id}')" style="flex:1;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:8px;padding:.4rem .7rem;font-size:.8rem;font-weight:700;cursor:pointer;color:#334155">✏️ Edit</button>
        <button onclick="toggleCompanyActive('${c.id}')" style="flex:1;background:${c.active?'#FFF7ED':'#F0FDF4'};border:1px solid ${c.active?'#FED7AA':'#86EFAC'};border-radius:8px;padding:.4rem .7rem;font-size:.8rem;font-weight:700;cursor:pointer;color:${c.active?'#C2410C':'#16A34A'}">${c.active?'Deactivate':'Activate'}</button>
      </div>
    </div>
  `).join('');
}

function filterRentalCos(city, btn) {
  document.querySelectorAll('#rc-city-chips .fchip').forEach(b => b.classList.remove('active'));
  btn.classList.add('active');
  renderRentalCompanies(city === 'all' ? null : city);
}

function openAddCompanyModal() {
  { const _el_acm_title = document.getElementById('acm-title'); if (_el_acm_title) _el_acm_title.textContent = '🏢 Add Rental Company'; }
  document.getElementById('acm-edit-id').value = '';
  ['acm-name','acm-email','acm-phone','acm-address'].forEach(id => { const el = document.getElementById(id); if (el) el.value = ''; });
  const bc = document.getElementById('acm-base-city'); if (bc) bc.value = '';
  const rad = document.getElementById('acm-radius'); if (rad) rad.value = '75';
  document.getElementById('acm-active').value = '1';
  initAcmSectorGrid([]);
  document.getElementById('add-company-modal').classList.add('open');
}

function initAcmSectorGrid(selected) {
  const grid = document.getElementById('acm-sectors-grid');
  if (!grid) return;
  const sel = selected.map(s => s.toLowerCase());
  if (grid) grid.innerHTML = EQUIPMENT_SECTORS.map(s => `
    <label style="display:flex;align-items:center;gap:.4rem;font-size:.82rem;color:#334155;cursor:pointer;padding:.22rem .1rem;user-select:none">
      <input type="checkbox" value="${s}" ${sel.includes(s.toLowerCase()) ? 'checked' : ''}
        style="accent-color:#0052CC;width:14px;height:14px;cursor:pointer;flex-shrink:0">
      ${s}
    </label>`).join('');
}

function closeAddCompanyModal() {
  document.getElementById('add-company-modal').classList.remove('open');
}

function editCompany(id) {
  const c = RENTAL_COMPANIES.find(x => x.id === id);
  if (!c) return;
  { const _el_acm_title = document.getElementById('acm-title'); if (_el_acm_title) _el_acm_title.textContent = '✏️ Edit Rental Company'; }
  document.getElementById('acm-edit-id').value = id;
  document.getElementById('acm-name').value     = c.name;
  document.getElementById('acm-email').value    = c.email;
  document.getElementById('acm-phone').value    = c.phone || '';
  document.getElementById('acm-address').value  = c.address || '';
  document.getElementById('acm-active').value   = c.active ? '1' : '0';
  const bc = document.getElementById('acm-base-city');
  if (bc) bc.value = c.baseCity || (c.cities && c.cities[0]) || '';
  const rad = document.getElementById('acm-radius');
  if (rad) rad.value = String(c.serviceRadiusKm || 75);
  initAcmSectorGrid(c.sectors || (c.machines ? c.machines.split(',').map(s=>s.trim()) : []));
  document.getElementById('add-company-modal').classList.add('open');
}

function saveCompany() {
  const name     = document.getElementById('acm-name').value.trim();
  const email    = document.getElementById('acm-email').value.trim();
  const baseCity = (document.getElementById('acm-base-city')?.value || '').trim();
  const radius   = parseInt(document.getElementById('acm-radius')?.value || '75', 10);
  if (!name)     { showToast('Company name is required','#EF4444'); return; }
  if (!email)    { showToast('Email is required','#EF4444'); return; }
  if (!baseCity) { showToast('Please select a depot city','#EF4444'); return; }
  const editId = document.getElementById('acm-edit-id').value;
  const sectors = [...document.querySelectorAll('#acm-sectors-grid input[type=checkbox]:checked')].map(cb => cb.value);
  const payload = {
    name, email, baseCity,
    serviceRadiusKm: radius,
    cities: [baseCity], // keep cities for legacy compat
    phone:    document.getElementById('acm-phone').value.trim(),
    address:  document.getElementById('acm-address').value.trim(),
    machines: sectors.join(', '),
    sectors,
    active:   document.getElementById('acm-active').value === '1'
  };
  if (editId) {
    const idx = RENTAL_COMPANIES.findIndex(c => c.id === editId);
    if (idx > -1) RENTAL_COMPANIES[idx] = { ...RENTAL_COMPANIES[idx], ...payload };
    showToast('Company updated', '#16A34A');
  } else {
    payload.id = 'rc' + Date.now();
    RENTAL_COMPANIES.push(payload);
    showToast('Company added', '#16A34A');
  }
  closeAddCompanyModal();
  renderRentalCompanies();
}

function toggleCompanyActive(id) {
  const c = RENTAL_COMPANIES.find(x => x.id === id);
  if (c) { c.active = !c.active; renderRentalCompanies(); }
}

