// Customer company registry — keyed by email domain or full email
// Staff can expand this list. Matched by full email first, then @domain.
var CUSTOMER_ORGS = [
  { match:'@acmeconstruction.com.au', company:'ACME Construction Pty Ltd',  address:'12 Builder Way, Parramatta NSW 2150' },
  { match:'@bricksmortar.com.au',     company:'Bricks & Mortar Group',       address:'88 Trade St, Blacktown NSW 2148' },
  // Add more customer orgs here — admin/rental @noyo.com.au users are handled by the role-based path in getEffectiveOrg()
];

function getCustomerOrg(email) {
  if (!email) return null;
  const e = email.toLowerCase();
  // Exact match first
  let org = CUSTOMER_ORGS.find(o => o.match === e);
  if (org) return org;
  // Domain match
  const domain = e.includes('@') ? '@' + e.split('@')[1] : null;
  if (domain) org = CUSTOMER_ORGS.find(o => o.match === domain);
  return org || null;
}

function generateQuoteRef() {
  const now = new Date();
  const yy  = String(now.getFullYear()).slice(2);
  const mm  = String(now.getMonth()+1).padStart(2,'0');
  const dd  = String(now.getDate()).padStart(2,'0');
  const seq = String(Math.floor(Math.random()*9000)+1000);
  return `QR-${yy}${mm}${dd}-${seq}`;
}

function openForm(type, pendingView) {
  const wrap  = document.getElementById('lp-form-wrap');
  const form  = document.getElementById('lp-form');
  const title = document.getElementById('lp-form-title');
  const sub   = document.getElementById('lp-form-sub');
  const btn   = document.getElementById('lp-submit-btn');
  const errEl = document.getElementById('lp-error');
  if (errEl) errEl.textContent = '';

  ['lp-email','lp-pass','lp-name','lp-company','lp-abn','lp-mobile','lp-address','lp-suburb','lp-city','lp-state']
    .forEach(id => { const el = document.getElementById(id); if (el) el.value = ''; });
  document.querySelectorAll('#lp-cats-grid input[type=checkbox]').forEach(cb => cb.checked = false);

  wrap._loginType   = type;
  wrap._authMode    = 'signin';
  wrap._pendingView = pendingView || 'finder';
  form.classList.remove('register-mode');
  document.querySelectorAll('.lp-reg-only').forEach(el => el.style.display = 'none');

  const toggle = document.getElementById('lp-toggle');
  const _tabSI = document.getElementById('lp-tab-signin');
  const _tabReg = document.getElementById('lp-tab-register');
  if (_tabSI) _tabSI.classList.add('active');
  if (_tabReg) _tabReg.classList.remove('active');
  if (toggle) toggle.style.display = 'flex';

  if (type === 'rental') {
    if (title) title.textContent = 'Rental Company Portal';
    if (sub) sub.textContent   = 'Sign in or register your company';
    if (btn) { btn.className = 'lp-submit rental'; btn.textContent = 'Sign In'; }
  } else if (type === 'lite') {
    if (title) title.textContent = 'Noyo Lite — Machine Finder';
    if (sub) sub.textContent   = 'For information only — no quoting or pricing';
    if (btn) { btn.className = 'lp-submit lite'; btn.textContent = 'Sign In'; }
  } else {
    if (title) title.textContent = 'Customer Access';
    if (sub) sub.textContent   = 'Sign in or create an account';
    if (btn) { btn.className = 'lp-submit customer-s'; btn.textContent = 'Sign In'; }
  }
  wrap.classList.add('visible');
  setTimeout(() => document.getElementById('lp-email').focus(), 200);
}

function setAuthMode(mode) {
  const wrap = document.getElementById('lp-form-wrap');
  const form = document.getElementById('lp-form');
  wrap._authMode = mode;
  const btn       = document.getElementById('lp-submit-btn');
  const signinTab = document.getElementById('lp-tab-signin');
  const regTab    = document.getElementById('lp-tab-register');
  const errEl     = document.getElementById('lp-error');
  if (errEl) errEl.textContent = '';
  const regFields = document.querySelectorAll('.lp-reg-only');

  const isRental = (wrap._loginType === 'rental');
  const isLite   = (wrap._loginType === 'lite');
  if (mode === 'register') {
    // Clear all fields fresh every time Register tab is opened — never carry over data from a previous session
    ['lp-name','lp-company','lp-abn','lp-mobile','lp-address','lp-suburb','lp-city','lp-state','lp-lite-address']
      .forEach(id => { const el = document.getElementById(id); if (el) el.value = ''; });
    const liteDepot = document.getElementById('lp-lite-depot');
    if (liteDepot) liteDepot.value = '';
    document.querySelectorAll('#lp-cats-grid input[type=checkbox]').forEach(cb => cb.checked = false);
    regFields.forEach(el => {
      if (el.classList.contains('lp-rental-only')) {
        el.style.display = isRental ? '' : 'none';
      } else if (el.classList.contains('lp-customer-only')) {
        el.style.display = (isRental || isLite) ? 'none' : '';
      } else if (el.classList.contains('lp-lite-only')) {
        el.style.display = isLite ? '' : 'none';
      } else {
        // shared reg fields: hide company row for lite
        if (isLite && el.querySelector && el.querySelector('#lp-company')) {
          el.style.display = 'none';
        } else {
          el.style.display = el.classList.contains('lp-row-2') ? 'flex' : '';
        }
      }
    });
    // Reset T&C checkboxes every time Register tab opens
    const rCb = document.getElementById('lp-tnc-rental-cb');
    const cCb = document.getElementById('lp-tnc-customer-cb');
    const lCb = document.getElementById('lp-tnc-lite-cb');
    if (rCb) rCb.checked = false;
    if (cCb) cCb.checked = false;
    if (lCb) lCb.checked = false;
    form.classList.add('register-mode');
    btn.textContent = isRental ? 'Register Company' : isLite ? 'Create Lite Account' : 'Create Account';
    // update button colour for lite
    if (isLite) { btn.className = 'lp-submit lite'; }
    signinTab.classList.remove('active');
    regTab.classList.add('active');
    _initAddressAutocomplete();
    setTimeout(() => document.getElementById('lp-name').focus(), 50);
  } else {
    regFields.forEach(el => el.style.display = 'none');
    form.classList.remove('register-mode');
    btn.textContent = 'Sign In';
    signinTab.classList.add('active');
    regTab.classList.remove('active');
    // Clear checkboxes when switching back to sign-in
    document.querySelectorAll('#lp-cats-grid input[type=checkbox]').forEach(cb => cb.checked = false);
    setTimeout(() => document.getElementById('lp-email').focus(), 50);
  }
}


// Returns array of {suburb, city, state, display} for dropdown rendering.
// For ambiguous suburbs, returns ALL city variants so user can choose.
function _suburbMatches(query) {
  var q = query.toLowerCase().trim();
  var results = [];
  var seen = new Set();

  // Check AU_SUBURB_MULTI first — exact match for ambiguous suburbs
  if (AU_SUBURB_MULTI[q]) {
    AU_SUBURB_MULTI[q].forEach(function(cs) {
      var key = q + '|' + cs[0];
      if (!seen.has(key)) {
        seen.add(key);
        results.push({ suburb: q, city: cs[0], state: cs[1] });
      }
    });
    return results;
  }

  // Prefix search: check for ambiguous suburbs whose name starts with query
  if (q.length >= 2) {
    Object.keys(AU_SUBURB_MULTI).forEach(function(base) {
      if (base.startsWith(q) && results.length < 12) {
        AU_SUBURB_MULTI[base].forEach(function(cs) {
          var key = base + '|' + cs[0];
          if (!seen.has(key)) {
            seen.add(key);
            results.push({ suburb: base, city: cs[0], state: cs[1] });
          }
        });
      }
    });
    if (results.length > 0) return results;
  }

  // Regular single-city lookup
  Object.keys(AU_SUBURB_CITY).forEach(function(key) {
    if (key.startsWith(q) && results.length < 8) {
      // Skip state-qualified keys in default results (they're fallbacks)
      if (/ (nsw|vic|qld|wa|sa|tas|nt|act)$/.test(key)) return;
      var cs = AU_SUBURB_CITY[key];
      if (!cs) return;
      var seenKey = key + '|' + cs[0];
      if (!seen.has(seenKey)) {
        seen.add(seenKey);
        results.push({ suburb: key, city: cs[0], state: cs[1] });
      }
    }
  });
  return results.slice(0, 8);
}

// ── Registration suburb autocomplete (uses AU_SUBURB_CITY) ──────────
var _lpSuburbItems = [], _lpSuburbFocus = -1;

function _initAddressAutocomplete() { /* suburb handled by _suburbInput */ }

// Detect if user typed a suburb name into the address field and offer to move it
function _lpAddressInput(val) {
  const hint = document.getElementById('lp-address-suburb-hint');
  if (!hint) return;
  if (!val || val.length < 3) { hint.style.display = 'none'; return; }

  const q = val.trim().toLowerCase();

  // Only trigger if the input looks like a suburb name (no digits = no street number)
  if (/\d/.test(q)) { hint.style.display = 'none'; return; }

  const match = AU_SUBURB_CITY[q] || (() => {
    const key = Object.keys(AU_SUBURB_CITY).find(k => k === q || k.startsWith(q));
    return key ? AU_SUBURB_CITY[key] : null;
  })();

  if (match) {
    hint.dataset.suburb = val.trim();
    hint.dataset.city   = match[0];
    hint.dataset.state  = match[1];
    hint.innerHTML = `💡 <strong>"${val.trim()}"</strong> looks like a suburb in ${match[0]}, ${match[1]}. Tap to move it to the <strong>Depot Suburb</strong> field instead.`;
    hint.style.display = '';
  } else {
    hint.style.display = 'none';
  }
}

function _lpAddressHintAccept() {
  const hint = document.getElementById('lp-address-suburb-hint');
  if (!hint) return;
  const suburb = hint.dataset.suburb || '';
  const city   = hint.dataset.city   || '';
  const state  = hint.dataset.state  || '';

  // Clear the address field and move value to suburb
  const addrEl   = document.getElementById('lp-address');
  const suburbEl = document.getElementById('lp-suburb');
  const cityEl   = document.getElementById('lp-city');
  const stateEl  = document.getElementById('lp-state');
  if (addrEl)   addrEl.value   = '';
  if (suburbEl) suburbEl.value = suburb.replace(/\b\w/g, c => c.toUpperCase());
  if (cityEl)   cityEl.value   = city;
  if (stateEl)  stateEl.value  = state;
  hint.style.display = 'none';
  // Focus address field so user can type the actual street address
  if (addrEl) addrEl.focus();
  showToast(`✅ "${suburb}" moved to Depot Suburb — now enter your street address above.`, '#16A34A');
}

function _suburbInput(val) {
  _lpSuburbFocus = -1;
  const drop = document.getElementById('lp-suburb-drop');
  if (!drop) return;

  // Clear city/state whenever user edits suburb so stale values don't linger
  const cityEl  = document.getElementById('lp-city');
  const stateEl = document.getElementById('lp-state');
  if (cityEl)  cityEl.value  = '';
  if (stateEl) stateEl.value = '';

  if (!val || val.length < 2) { drop.style.display = 'none'; return; }
  const q = val.toLowerCase().trim();
  _lpSuburbItems = _suburbMatches(q);
  if (!_lpSuburbItems.length) { drop.style.display = 'none'; return; }

  // Auto-fill city/state only if exactly one option (otherwise user must pick)
  const exactIdx = _lpSuburbItems.findIndex(it => it.suburb === q);
  if (_lpSuburbItems.length === 1) {
    const auto = _lpSuburbItems[0];
    if (cityEl)  cityEl.value  = auto.city;
    if (stateEl) stateEl.value = auto.state;
  }

  drop.innerHTML = _lpSuburbItems.map((it, i) =>
    `<div class="lp-suburb-item" data-i="${i}"
       onmousedown="event.preventDefault();_suburbSelect(${i})"
       onmouseover="_lpSuburbHover(this,${i})"
       onmouseout="this.classList.remove('focused')">
       <strong>${(it.suburb||'?').replace(/\b\w/g,c=>c.toUpperCase())}</strong><span>${it.city}, ${it.state}</span>
    </div>`
  ).join('');
  drop.style.display = '';
}

function _lpSuburbHover(el, i) {
  _lpSuburbFocus = i;
  const drop = document.getElementById('lp-suburb-drop');
  if (drop) drop.querySelectorAll('.lp-suburb-item').forEach((x,j)=>x.classList.toggle('focused',j===i));
}

function _suburbSelect(i) {
  const it = _lpSuburbItems[i];
  if (!it) return;
  const formatted = (it.suburb||'?').replace(/\b\w/g,c=>c.toUpperCase());
  const inp = document.getElementById('lp-suburb');
  if (inp) inp.value = formatted;
  const cityEl  = document.getElementById('lp-city');
  const stateEl = document.getElementById('lp-state');
  if (cityEl)  cityEl.value  = it.city;
  if (stateEl) stateEl.value = it.state;
  const drop = document.getElementById('lp-suburb-drop');
  if (drop) drop.style.display = 'none';
}

function _suburbBlur() {
  setTimeout(() => {
    const drop = document.getElementById('lp-suburb-drop');
    if (drop) drop.style.display = 'none';

    // ── Auto-fill city/state from whatever the user typed, if not already set ──
    const inp    = document.getElementById('lp-suburb');
    const cityEl = document.getElementById('lp-city');
    const stEl   = document.getElementById('lp-state');
    if (!inp || !cityEl || !stEl) return;

    const typed = inp.value.trim().toLowerCase();
    if (!typed) return;

    // If city is already filled (user picked from dropdown), nothing to do
    if (cityEl.value.trim()) return;

    // Try exact key match first, then startsWith to catch partially-typed names
    let result = AU_SUBURB_CITY[typed];
    if (!result) {
      const key = Object.keys(AU_SUBURB_CITY).find(k => k.startsWith(typed));
      if (key) {
        // Update the displayed suburb text to the full matched suburb name
        inp.value = key.replace(/\b\w/g, c => c.toUpperCase());
        result = AU_SUBURB_CITY[key];
      }
    }
    if (result) {
      cityEl.value = result[0];
      stEl.value   = result[1];
    }
  }, 200);
}

function _suburbFocus() {
  // Reopen dropdown when user clicks back into the field to retype
  const val = (document.getElementById('lp-suburb')?.value || '').trim();
  if (val.length >= 2) _suburbInput(val);
}

function _suburbKey(e) {
  const drop = document.getElementById('lp-suburb-drop');
  const items = drop ? drop.querySelectorAll('.lp-suburb-item') : [];
  if (!items.length) return;
  if (e.key === 'ArrowDown') {
    e.preventDefault();
    _lpSuburbFocus = Math.min(_lpSuburbFocus + 1, items.length - 1);
    items.forEach((el,i) => el.classList.toggle('focused', i === _lpSuburbFocus));
  } else if (e.key === 'ArrowUp') {
    e.preventDefault();
    _lpSuburbFocus = Math.max(_lpSuburbFocus - 1, 0);
    items.forEach((el,i) => el.classList.toggle('focused', i === _lpSuburbFocus));
  } else if (e.key === 'Enter' && _lpSuburbFocus >= 0) {
    e.preventDefault();
    _suburbSelect(_lpSuburbFocus);
  } else if (e.key === 'Tab' && _lpSuburbFocus >= 0) {
    e.preventDefault();
    _suburbSelect(_lpSuburbFocus);
  } else if (e.key === 'Escape') {
    if (drop) drop.style.display = 'none';
  }
}

function closeForm() {
  document.getElementById('lp-form-wrap').classList.remove('visible');
  document.getElementById('lp-form').classList.remove('register-mode');
  const errEl = document.getElementById('lp-error');
  if (errEl) errEl.textContent = '';
}

function doLogin() {
  const wrap  = document.getElementById('lp-form-wrap');
  const email = document.getElementById('lp-email').value.trim().toLowerCase();
  const pass  = document.getElementById('lp-pass').value;
  const errEl = document.getElementById('lp-error');
  const type  = wrap._loginType;
  const mode  = wrap._authMode || 'signin';

  if (!email || !pass) { errEl.textContent = 'Please enter email and password.'; return; }

  // ── RENTAL REGISTRATION ──────────────────────────────────────────────
  if (type === 'rental' && mode === 'register') {
    const tncCb = document.getElementById('lp-tnc-rental-cb');
    if (!tncCb || !tncCb.checked) {
      errEl.textContent = '⚠️ Please read and accept the Noyo Terms & Conditions to register.';
      document.getElementById('lp-tnc-rental').scrollIntoView({ behavior: 'smooth', block: 'center' });
      return;
    }
    const fullName = (document.getElementById('lp-name').value    || '').trim();
    const company  = (document.getElementById('lp-company').value  || '').trim();
    const mobile   = (document.getElementById('lp-mobile').value   || '').trim();
    const address  = (document.getElementById('lp-address').value  || '').trim();
    const suburb   = (document.getElementById('lp-suburb').value   || '').trim();
    let city  = (document.getElementById('lp-city').value  || '').trim();
    let state = (document.getElementById('lp-state').value || '').trim();
    if (suburb && !city) {
      const looked = AU_SUBURB_CITY[suburb.toLowerCase()]
        || AU_SUBURB_CITY[Object.keys(AU_SUBURB_CITY).find(k => k.startsWith(suburb.toLowerCase())) || ''];
      if (looked) { city = looked[0]; state = looked[1]; }
    }
    if (city)  document.getElementById('lp-city').value  = city;
    if (state) document.getElementById('lp-state').value = state;
    const abn    = (document.getElementById('lp-abn')?.value     || '').trim();
    const radius = parseInt(document.getElementById('lp-radius')?.value || '75', 10);
    const cats   = [...document.querySelectorAll('#lp-cats-grid input[type=checkbox]:checked')].map(cb => cb.value);
    const _ruralOptIn = document.getElementById('lp-rural-optin');
    const _ruralRad   = document.getElementById('lp-rural-radius');
    const ruralOptIn  = _ruralOptIn ? _ruralOptIn.checked : false;
    const ruralRadiusKm = ruralOptIn ? parseInt(_ruralRad ? _ruralRad.value : '500', 10) : 0;

    if (!fullName) { errEl.textContent = 'Please enter your full name.';     return; }
    if (!company)  { errEl.textContent = 'Please enter your company name.';  return; }
    if (!abn || abn.replace(/\s/g,'').length < 11) { errEl.textContent = 'Please enter a valid 11-digit ABN.'; return; }
    if (!mobile)   { errEl.textContent = 'Please enter your mobile number.'; return; }
    if (!address)  { errEl.textContent = 'Please enter your street address.'; return; }
    if (!suburb)   { errEl.textContent = 'Please select your suburb.';       return; }
    if (!city)     { errEl.textContent = 'Suburb not recognised — please select from the dropdown suggestions.'; return; }
    if (!cats.length) { errEl.textContent = 'Please select at least one equipment category.'; return; }

    errEl.textContent = '';
    const btn = document.getElementById('lp-submit-btn');
    if (btn) { btn.disabled = true; btn.textContent = 'Registering…'; }

    _fbAuth.createUserWithEmailAndPassword(email, pass)
      .then(async cred => {
        const uid = cred.user.uid;
        const userDoc = {
          uid, email, fullName, role: 'rental', active: true,
          approvalStatus: 'pending', registeredAt: new Date().toISOString(),
          createdAt: firebase.firestore.FieldValue.serverTimestamp()
        };
        const rentalDoc = {
          userId: uid, email, companyName: company, abn, phone: mobile,
          address, suburb, city, state, serviceRadiusKm: radius,
          baseCity: city, sectors: cats, active: false,
          ruralOptIn, ruralRadiusKm,
          approvalStatus: 'pending', registeredAt: new Date().toISOString(),
          createdAt: firebase.firestore.FieldValue.serverTimestamp()
        };
        await _fbDb.collection('users').doc(uid).set(userDoc);
        await _fbDb.collection('rental_profiles').doc(uid).set(rentalDoc);
        _userProfileCache[uid] = { ...userDoc, ...rentalDoc };
        if (btn) { btn.disabled = false; btn.textContent = 'Register'; }
        closeForm();
        showToast('✅ Registration received! Your account is pending admin approval — usually within 1 business day.', '#16A34A');
      })
      .catch(err => {
        if (btn) { btn.disabled = false; btn.textContent = 'Register'; }
        if (err.code === 'auth/email-already-in-use') {
          errEl.textContent = 'This email is already registered. Please sign in instead.';
        } else if (err.code === 'auth/weak-password') {
          errEl.textContent = 'Password must be at least 6 characters.';
        } else {
          errEl.textContent = 'Registration failed: ' + err.message;
        }
        shake();
      });
    return;
  }

  // ── LITE REGISTRATION ─────────────────────────────────────────────────
  if (type === 'lite' && mode === 'register') {
    const tncCbLite = document.getElementById('lp-tnc-lite-cb');
    if (!tncCbLite || !tncCbLite.checked) {
      errEl.textContent = '⚠️ Please read and accept the Noyo Lite Terms of Use to register.';
      document.getElementById('lp-tnc-lite').scrollIntoView({ behavior: 'smooth', block: 'center' });
      return;
    }
    const fullName  = (document.getElementById('lp-name').value      || '').trim();
    const mobile    = (document.getElementById('lp-mobile').value     || '').trim();
    const address   = (document.getElementById('lp-lite-address').value || '').trim();
    const depot     = (document.getElementById('lp-lite-depot').value  || '').trim();

    if (!fullName) { errEl.textContent = 'Please enter your full name.';       return; }
    if (!mobile)   { errEl.textContent = 'Please enter your mobile number.';   return; }
    if (!address)  { errEl.textContent = 'Please enter your street address.';  return; }
    if (!depot)    { errEl.textContent = 'Please select your nearest depot city.'; return; }

    errEl.textContent = '';
    const btn = document.getElementById('lp-submit-btn');
    if (btn) { btn.disabled = true; btn.textContent = 'Registering…'; }

    _fbAuth.createUserWithEmailAndPassword(email, pass)
      .then(async cred => {
        const uid = cred.user.uid;
        const userDoc = {
          uid, email, fullName, role: 'lite', active: true,
          phone: mobile, address, depot,
          createdAt: firebase.firestore.FieldValue.serverTimestamp()
        };
        await _fbDb.collection('users').doc(uid).set(userDoc);
        _userProfileCache[uid] = userDoc;
        if (btn) { btn.disabled = false; btn.textContent = 'Create Lite Account'; }
        loginSuccess({ name: fullName, role: 'lite', email, uid, depot });
      })
      .catch(err => {
        if (btn) { btn.disabled = false; btn.textContent = 'Create Lite Account'; }
        if (err.code === 'auth/email-already-in-use') {
          errEl.textContent = 'This email is already registered. Please sign in instead.';
        } else if (err.code === 'auth/weak-password') {
          errEl.textContent = 'Password must be at least 6 characters.';
        } else {
          errEl.textContent = 'Registration failed: ' + err.message;
        }
        shake();
      });
    return;
  }

  // ── CUSTOMER REGISTRATION ────────────────────────────────────────────
  if (type !== 'rental' && mode === 'register') {
    const tncCbCust = document.getElementById('lp-tnc-customer-cb');
    if (!tncCbCust || !tncCbCust.checked) {
      errEl.textContent = '⚠️ Please read and accept the Noyo Terms & Conditions to register.';
      document.getElementById('lp-tnc-customer').scrollIntoView({ behavior: 'smooth', block: 'center' });
      return;
    }
    const fullName = (document.getElementById('lp-name').value    || '').trim();
    const company  = (document.getElementById('lp-company').value  || '').trim();
    const mobile   = (document.getElementById('lp-mobile').value   || '').trim();
    const address  = (document.getElementById('lp-address').value  || '').trim();
    const suburb   = (document.getElementById('lp-suburb').value   || '').trim();
    let city  = (document.getElementById('lp-city').value  || '').trim();
    let state = (document.getElementById('lp-state').value || '').trim();
    if (suburb && !city) {
      const looked = AU_SUBURB_CITY[suburb.toLowerCase()]
        || AU_SUBURB_CITY[Object.keys(AU_SUBURB_CITY).find(k => k.startsWith(suburb.toLowerCase())) || ''];
      if (looked) { city = looked[0]; state = looked[1]; }
    }
    if (!fullName) { errEl.textContent = 'Please enter your full name.';     return; }
    if (!company)  { errEl.textContent = 'Please enter your company name.';  return; }
    if (!mobile)   { errEl.textContent = 'Please enter your mobile number.'; return; }
    if (!address)  { errEl.textContent = 'Please enter your street address.'; return; }
    if (!suburb)   { errEl.textContent = 'Please select your suburb.';       return; }

    const btn = document.getElementById('lp-submit-btn');
    if (btn) { btn.disabled = true; btn.textContent = 'Registering…'; }

    _fbAuth.createUserWithEmailAndPassword(email, pass)
      .then(async cred => {
        const uid = cred.user.uid;
        const userDoc = {
          uid, email, fullName, role: 'customer', active: true,
          companyName: company, phone: mobile, address, suburb, city, state,
          createdAt: firebase.firestore.FieldValue.serverTimestamp()
        };
        await _fbDb.collection('users').doc(uid).set(userDoc);
        _userProfileCache[uid] = userDoc;
        if (btn) { btn.disabled = false; btn.textContent = 'Register'; }
        loginSuccess({ name: fullName, role: 'customer', email, uid });
      })
      .catch(err => {
        if (btn) { btn.disabled = false; btn.textContent = 'Register'; }
        if (err.code === 'auth/email-already-in-use') {
          errEl.textContent = 'This email is already registered. Please sign in instead.';
        } else if (err.code === 'auth/weak-password') {
          errEl.textContent = 'Password must be at least 6 characters.';
        } else {
          errEl.textContent = 'Registration failed: ' + err.message;
        }
        shake();
      });
    return;
  }

  // ── SIGN IN (rental or customer) ─────────────────────────────────────
  const btn = document.getElementById('lp-submit-btn');
  if (btn) { btn.disabled = true; btn.textContent = 'Signing in…'; }

  _fbAuth.signInWithEmailAndPassword(email, pass)
    .then(async cred => {
      const uid = cred.user.uid;
      // Load profile from Firestore
      const profile = await _fbLoadUserProfile(uid);
      const role = profile.role || 'customer';
      const name = profile.fullName || email.split('@')[0];

      // If rental, also load rental profile into RENTAL_COMPANIES
      if (role === 'rental' || role === 'staff' || role === 'manager' || role === 'admin') {
        const rp = await _fbLoadRentalProfile(uid);
        if (rp) {
          _userProfileCache[uid] = { ..._userProfileCache[uid], ...rp };
          const rcEntry = {
            id: uid, name: rp.companyName || name, email,
            phone: rp.phone || '', address: rp.address || '',
            baseCity: rp.city || '', serviceRadiusKm: rp.serviceRadiusKm || 75,
            cities: [rp.city || ''], machines: (rp.sectors||[]).join(', '),
            sectors: rp.sectors || [], active: rp.active !== false,
            ruralOptIn: rp.ruralOptIn || false, ruralRadiusKm: rp.ruralRadiusKm || 0
          };
          const existIdx = RENTAL_COMPANIES.findIndex(c => c.email === email);
          if (existIdx > -1) RENTAL_COMPANIES[existIdx] = { ...RENTAL_COMPANIES[existIdx], ...rcEntry };
          else RENTAL_COMPANIES.push(rcEntry);

          // Check approval status for rental users
          if (role === 'rental' && rp.approvalStatus === 'pending') {
            if (btn) { btn.disabled = false; btn.textContent = 'Sign In'; }
            errEl.textContent = '⏳ Your account is pending admin approval. You will be notified once reviewed — usually within 1 business day.';
            errEl.style.color = '#B45309';
            errEl.style.display = 'block';
            _fbAuth.signOut();
            return;
          }
          if (role === 'rental' && rp.approvalStatus === 'rejected') {
            if (btn) { btn.disabled = false; btn.textContent = 'Sign In'; }
            errEl.textContent = '❌ Your application has not been approved. Please contact sales@noyo.com.au for more information.';
            _fbAuth.signOut();
            return;
          }
        }
      }

      if (btn) { btn.disabled = false; btn.textContent = 'Sign In'; }
      loginSuccess({ name, role, email, uid, depot: profile.depot || '' });
    })
    .catch(err => {
      if (btn) { btn.disabled = false; btn.textContent = 'Sign In'; }
      if (err.code === 'auth/user-not-found' || err.code === 'auth/wrong-password' || err.code === 'auth/invalid-credential') {
        errEl.textContent = 'Incorrect email or password.';
      } else {
        errEl.textContent = 'Sign in failed: ' + err.message;
      }
      shake();
    });
}

function loginSuccess(user) {
  currentUser = user;
  // Ensure uid is always on currentUser (from Firebase Auth or passed directly)
  if (!currentUser.uid && _fbAuth.currentUser) {
    currentUser.uid = _fbAuth.currentUser.uid;
  }
  _sessionRegisteredOrg = null; // always start fresh — no bleed from previous session

  // For scustomer demo accounts: clear any stale company/ABN data from previous sessions
  // so they always see a clean registration form
  if (user.email && user.email.match(/^scustomer\d+@noyo\.com\.au$/i)) {
    try {
      ['company','abn','address','suburb','city','state','mobile'].forEach(field => {
        localStorage.removeItem('noyo_acct_' + field + '_' + user.email.toLowerCase());
      });
    } catch(e) {}
  }

  // ── Restore saved cart for this user ──
  loadCartFromStorage(user.email);
  updateCartUI();
  // ── Admin tracking ──
  try { adminTrackLogin(user); } catch(e) {}
  // Hide portal — belt-and-suspenders approach
  const _portal = document.getElementById('login-portal');
  if (_portal) { _portal.classList.add('hidden'); _portal.style.display = 'none'; _portal.setAttribute('aria-hidden','true'); }

  // Update nav pill
  const pill    = document.getElementById('nav-user-pill');
  const avatar  = document.getElementById('nav-avatar');
  const uname   = document.getElementById('nav-uname');
  const roleTag = document.getElementById('nav-role-tag');
  if (pill)    pill.style.display = 'block';
  if (avatar)  avatar.textContent = user.name.charAt(0).toUpperCase();
  if (uname)   uname.textContent  = user.name;

  if (user.role === 'rental' || user.role === 'admin') {
    if (avatar)  avatar.className  = 'nav-avatar rental-av';
    if (roleTag) roleTag.textContent = user.role === 'admin' ? '⚙️ Admin' : 'Rental Co.';
    const mainTabs = document.getElementById('main-nav-tabs');
    if (mainTabs) mainTabs.style.display = 'flex';
    if (user.role === 'admin') {
      const tabAdm = document.getElementById('tab-admin');
      if (tabAdm) tabAdm.style.display = 'inline-flex';
      // Also show Quote Requests tab for admin
      const tabQR2 = document.getElementById('tab-quote-requests-wrap');
      if (tabQR2) tabQR2.style.display = 'inline-flex';
      // Admin/Manager also get My Quotes so they can see their OWN submitted enquiries as a customer
      const tabMQ2 = document.getElementById('tab-my-quotes-wrap');
      if (tabMQ2) tabMQ2.style.display = 'inline-flex';
      _resetWizardToHome();
      // Load historical analytics from Firestore, then render dashboard
      _loadAdminAnalyticsFromFirestore().then(() => renderAdminDashboard()).catch(() => renderAdminDashboard());
      switchView('admin', tabAdm || document.getElementById('tab-admin'));
    } else {
      // Show Quote Requests for rental company
      const tabQR = document.getElementById('tab-quote-requests-wrap');
      if (tabQR) tabQR.style.display = 'inline-flex';
      // Hide My Quotes (customer tab) for rental
      const tabMQHide = document.getElementById('tab-my-quotes-wrap');
      if (tabMQHide) tabMQHide.style.display = 'none';
      // My Details is in the avatar dropdown — keep nav tab hidden
      const tabDet = document.getElementById('tab-my-details');
      if (tabDet) tabDet.style.display = 'none';
      _resetWizardToHome();
      showView('finder');
    }
    renderQuoteInbox();
    renderRentalCompanies();
    setTimeout(updateQRUnreadBadge, 200);
    // Hide feedback FAB for rental/admin — only customers give feedback
    const _ffab = document.getElementById('feedback-fab');
    if (_ffab) _ffab.style.display = 'none';
    // Load latest quotes from Firebase
    loadInboxFromFirebase().then(() => { renderQuoteInbox(); renderMyQuotes(); updateQRUnreadBadge(); updateMQUnreadBadge(); }).catch(()=>{});
    _loadNotificationStateFromFirestore().catch(() => {});
  } else {
    if (user.role === 'lite') {
      if (avatar)  avatar.className  = 'nav-avatar lite-av';
      if (roleTag) roleTag.textContent = '🔵 Lite';
    } else {
      if (avatar)  avatar.className  = 'nav-avatar customer-av';
      if (roleTag) roleTag.textContent = 'Customer';
    }
    const tabs = document.querySelectorAll('.nav-tab');
    tabs.forEach(t => { if(t.dataset.view==='staff') t.style.display='none'; });
    const tabAdm2 = document.getElementById('tab-admin');
    if (tabAdm2) tabAdm2.style.display = 'none';
    // Show My Quotes for customer
    const tabMQ = document.getElementById('tab-my-quotes-wrap');
    if (tabMQ) tabMQ.style.display = 'inline-flex';
    // Hide Quote Requests (rental tab) for customer
    const tabQRHide = document.getElementById('tab-quote-requests-wrap');
    if (tabQRHide) tabQRHide.style.display = 'none';
    // My Details nav tab — hidden for customers (they use avatar menu)
    const tabMD2 = document.getElementById('tab-my-details');
    if (tabMD2) tabMD2.style.display = 'none';
    // Route to pending view — finder with optional KYM open
    const wrap2 = document.getElementById('lp-form-wrap');
    const dest = (wrap2 && wrap2._pendingView) || 'finder';
    _resetWizardToHome();
    showView('finder');
    if (dest === 'know') { setTimeout(kymOpen, 120); }
    setTimeout(updateQRUnreadBadge, 200);
    // Reload inbox from Firebase to pick up latest quotes from all devices
    loadInboxFromFirebase().then(() => { renderMyQuotes(); updateQRUnreadBadge(); updateMQUnreadBadge(); }).catch(()=>{});
    _loadNotificationStateFromFirestore().catch(() => {});
    // Show feedback FAB for customers
    const _ffab2 = document.getElementById('feedback-fab');
    if (_ffab2) _ffab2.style.display = 'flex';
    // Hide cart UI for rental users — they browse only
    if (user.role === 'rental') {
      ['cart-fab','hero-cart-btn','cart-sidebar','cart-overlay'].forEach(id => {
        const el = document.getElementById(id); if (el) el.style.display = 'none';
      });
    }
    // ── LITE MODE: hide all quoting/cart UI ──────────────────────────
    if (user.role === 'lite') {
      ['cart-fab','hero-cart-btn','cart-sidebar','cart-overlay'].forEach(id => {
        const el = document.getElementById(id); if (el) el.style.display = 'none';
      });
      // Hide My Quotes tab — lite users cannot quote
      const tabMQLite = document.getElementById('tab-my-quotes-wrap');
      if (tabMQLite) tabMQLite.style.display = 'none';
      // Mark body so CSS/JS can suppress cart buttons globally
      document.body.setAttribute('data-portal', 'lite');
    }
  }
}

function logOut() {
  // ── Admin tracking ──
  try { adminTrackLogout(currentUser); } catch(e) {}
  // Sign out from Firebase Auth
  _fbAuth.signOut().catch(e => console.warn('Firebase signOut error:', e.message));
  currentUser = null;
  _userProfileCache = {};
  _sessionRegisteredOrg = null; // clear any previous rental registration

  // Reset wizard to clean home page
  _resetWizardToHome();

  // Hide all user-specific tabs
  ['tab-admin','tab-my-details'].forEach(id => {
    const el = document.getElementById(id); if(el) el.style.display = 'none';
  });
  ['tab-my-quotes-wrap','tab-quote-requests-wrap'].forEach(id => {
    const el = document.getElementById(id); if(el) el.style.display = 'none';
  });

  // Hide the user pill
  const _pill = document.getElementById('nav-user-pill');
  if (_pill) _pill.style.display = 'none';

  // Switch back to finder view
  document.querySelectorAll('.view').forEach(v => v.classList.remove('active'));
  const _vf = document.getElementById('view-finder');
  if (_vf) _vf.classList.add('active');
  document.querySelectorAll('.nav-tab').forEach(t => t.classList.remove('active'));
  const _finderTab = document.querySelector('.nav-tab[onclick*="finder"]');
  if (_finderTab) _finderTab.classList.add('active');

  // Show login portal
  const _portal2 = document.getElementById('login-portal');
  if (_portal2) _portal2.style.display = '';
  _portal2.removeAttribute('aria-hidden');
  if (_portal2) _portal2.classList.remove('hidden');
  document.getElementById('lp-form-wrap').classList.remove('visible');
  // Clear portal mode flag
  document.body.removeAttribute('data-portal');
}

// =====================================================================
// ADMIN DASHBOARD — TRACKING & RENDERING
// =====================================================================

// ── In-session tracking store ─────────────────────────────────────────
var adminData = {
  sessions:    [],  // {id, user, email, role, loginAt, logoutAt, searchCount, quoteCount}
  searches:    [],  // {id, ts, user, email, jobType, machineType, machineName, swl, height, city, cartAdded}
  quoteEvents: [],  // {ts, type:'sent'|'responded'|'broadcast', quoteId, ref, user, company, machines}
  activityLog: [],  // {ts, type, icon, title, meta, colorClass}
};

// Registered users = RENTAL_CREDS + any customers who log in this session
var customerRegistry = {}; // email → {name, role, loginCount, lastSeen, searchCount, quoteCount, status}

function adminTrackLogin(user) {
  const now = Date.now();
  const sid = 'sess_' + now;
  adminData.sessions.push({ id: sid, user: user.name, email: user.email, role: user.role, loginAt: now, logoutAt: null, searchCount: 0, quoteCount: 0 });
  if (!customerRegistry[user.email]) {
    customerRegistry[user.email] = { name: user.name, role: user.role, loginCount: 0, lastSeen: now, searchCount: 0, quoteCount: 0, status: 'online' };
  }
  const reg = customerRegistry[user.email];
  reg.loginCount++;
  reg.lastSeen = now;
  reg.status = 'online';
  const logEntry = { ts: now, type: 'login', icon: '🔐', colorClass: 'login', title: user.name + ' signed in', meta: user.role + ' · ' + user.email };
  adminData.activityLog.unshift(logEntry);
  // ── Firestore: persist login event ──
  if (_fbDb) {
    _fbDb.collection('admin_analytics').doc('activity_log').collection('events').add({
      ...logEntry, createdAt: firebase.firestore.FieldValue.serverTimestamp()
    }).catch(() => {});
    _fbDb.collection('admin_analytics').doc('user_registry').set(
      { [user.email]: { name: user.name, role: user.role, lastSeen: now, updatedAt: firebase.firestore.FieldValue.serverTimestamp() } },
      { merge: true }
    ).catch(() => {});
  }
}

function adminTrackLogout(user) {
  if (!user) return;
  const now = Date.now();
  const sess = [...adminData.sessions].reverse().find(s => s.email === user.email && !s.logoutAt);
  if (sess) sess.logoutAt = now;
  if (customerRegistry[user.email]) customerRegistry[user.email].status = 'inactive';
  const logEntry = { ts: now, type: 'logout', icon: '🚪', colorClass: 'logout', title: user.name + ' signed out', meta: user.role };
  adminData.activityLog.unshift(logEntry);
  // ── Firestore: persist logout event ──
  if (_fbDb) {
    _fbDb.collection('admin_analytics').doc('activity_log').collection('events').add({
      ...logEntry, createdAt: firebase.firestore.FieldValue.serverTimestamp()
    }).catch(() => {});
  }
}

function adminTrackSearch(result) {
  const now = Date.now();
  const user = currentUser || { name: 'Customer', email: 'unknown', role: 'customer' };
  const rec = {
    id: 'srch_' + now, ts: now, user: user.name, email: user.email,
    role: user.role || 'customer',
    depot: user.depot || '—',
    isLite: user.role === 'lite',
    jobType:     result.jobType     || '—',
    machineType: result.machineType || '—',
    machineName: result.machineName || '—',
    swl:         result.swl         || '—',
    load:        result.load        || result.swl || '—',
    height:      result.height      || '—',
    terrain:     result.terrain     || '—',
    power:       result.power       || result.powerPreference || '—',
    city:        result.city        || (user.role === 'lite' ? user.depot || '—' : '—'),
    cartAdded: false
  };
  adminData.searches.push(rec);
  if (customerRegistry[user.email]) {
    customerRegistry[user.email].searchCount++;
    customerRegistry[user.email].lastSeen = now;
    customerRegistry[user.email].status = 'online';
    if (!customerRegistry[user.email].cartAdds) customerRegistry[user.email].cartAdds = 0;
  }
  const sess = [...adminData.sessions].reverse().find(s => s.email === user.email && !s.logoutAt);
  if (sess) sess.searchCount++;
  const logEntry = { ts: now, type: 'search', icon: '🔍', colorClass: 'search',
    title: 'Search → ' + rec.machineName,
    meta: user.name + ' · ' + rec.jobType + (rec.city!=='—'?' · 📍'+rec.city:'') + (rec.height!=='—'?' · '+rec.height:'')
  };
  adminData.activityLog.unshift(logEntry);
  // ── Firestore: persist search record + activity event ──
  if (_fbDb) {
    _fbDb.collection('admin_analytics').doc('searches').collection('records').doc(rec.id).set({
      ...rec, createdAt: firebase.firestore.FieldValue.serverTimestamp()
    }).catch(() => {});
    _fbDb.collection('admin_analytics').doc('activity_log').collection('events').add({
      ...logEntry, createdAt: firebase.firestore.FieldValue.serverTimestamp()
    }).catch(() => {});
  }
  return rec.id;
}

function adminTrackCartAdd(searchId, machineName) {
  const rec = adminData.searches.find(s => s.id === searchId);
  if (rec) {
    rec.cartAdded = true;
    rec.machineName = machineName || rec.machineName;
    // Update Firestore record
    if (_fbDb) {
      _fbDb.collection('admin_analytics').doc('searches').collection('records').doc(searchId)
        .set({ cartAdded: true, machineName: rec.machineName }, { merge: true }).catch(() => {});
    }
  }
}

function adminTrackQuote(type, req) {
  const now = Date.now();
  const user = currentUser || { name: 'Unknown', email: '—' };
  const machines = (req.machines || []).map(m => m.name || m).join(', ') || '—';
  const quoteEvent = { ts: now, type, quoteId: req.id, ref: req.ref || req.id, user: user.name, email: user.email, machines, company: req.company || '—' };
  adminData.quoteEvents.push({ ...quoteEvent, req });
  if (customerRegistry[user.email]) {
    customerRegistry[user.email].quoteCount++;
    customerRegistry[user.email].lastSeen = now;
  }
  const sess = [...adminData.sessions].reverse().find(s => s.email === user.email && !s.logoutAt);
  if (sess) sess.quoteCount++;
  const icons = { sent: '📤', responded: '✅', broadcast: '📡' };
  const labels = { sent: 'Quote request sent', responded: 'Quote responded', broadcast: 'Enquiry broadcast to all companies' };
  const logEntry = { ts: now, type: 'quote', icon: icons[type] || '📨', colorClass: type === 'responded' ? 'respond' : 'quote',
    title: (labels[type] || 'Quote event') + ' · ' + (req.ref || req.id || ''), meta: user.name + ' · ' + machines };
  adminData.activityLog.unshift(logEntry);
  // ── Firestore: persist quote event + activity entry ──
  if (_fbDb) {
    _fbDb.collection('admin_analytics').doc('quote_events').collection('records').add({
      ...quoteEvent, createdAt: firebase.firestore.FieldValue.serverTimestamp()
    }).catch(() => {});
    _fbDb.collection('admin_analytics').doc('activity_log').collection('events').add({
      ...logEntry, createdAt: firebase.firestore.FieldValue.serverTimestamp()
    }).catch(() => {});
  }
}

function adminFmt(ts) {
  const d = new Date(ts);
  const now = new Date();
  const diff = (Date.now() - ts) / 1000;
  if (diff < 60) return 'Just now';
  if (diff < 3600) return Math.floor(diff / 60) + 'm ago';
  if (diff < 86400) return Math.floor(diff / 3600) + 'h ago';
  return d.toLocaleDateString('en-AU', { day: 'numeric', month: 'short' });
}

function adminFmtFull(ts) {
  return new Date(ts).toLocaleString('en-AU', { day: '2-digit', month: 'short', hour: '2-digit', minute: '2-digit' });
}

// ── Rendering ─────────────────────────────────────────────────────────

// ── Load admin analytics from Firestore (called when admin panel opens) ──
async function _loadAdminAnalyticsFromFirestore() {
  if (!_fbDb) return;
  try {
    // Load searches (last 500, ordered by time)
    const searchSnap = await _fbDb.collection('admin_analytics').doc('searches')
      .collection('records').orderBy('ts', 'desc').limit(500).get();
    const fsSearches = [];
    searchSnap.forEach(doc => fsSearches.push({ id: doc.id, ...doc.data() }));
    // Merge with in-memory (deduplicate by id)
    const searchMap = new Map();
    adminData.searches.forEach(s => searchMap.set(s.id, s));
    fsSearches.forEach(s => { if (!searchMap.has(s.id)) searchMap.set(s.id, s); });
    adminData.searches = [...searchMap.values()].sort((a, b) => (a.ts||0) - (b.ts||0));

    // Load activity log (last 200 events)
    const actSnap = await _fbDb.collection('admin_analytics').doc('activity_log')
      .collection('events').orderBy('ts', 'desc').limit(200).get();
    const fsActivity = [];
    actSnap.forEach(doc => fsActivity.push(doc.data()));
    // Merge with in-memory (deduplicate by ts+type+title)
    const actMap = new Map();
    adminData.activityLog.forEach(e => actMap.set(e.ts + '_' + e.type, e));
    fsActivity.forEach(e => { const k = e.ts + '_' + e.type; if (!actMap.has(k)) actMap.set(k, e); });
    adminData.activityLog = [...actMap.values()].sort((a, b) => (b.ts||0) - (a.ts||0));

    // Load quote events (last 200)
    const qeSnap = await _fbDb.collection('admin_analytics').doc('quote_events')
      .collection('records').orderBy('ts', 'desc').limit(200).get();
    const fsQE = [];
    qeSnap.forEach(doc => fsQE.push(doc.data()));
    const qeMap = new Map();
    adminData.quoteEvents.forEach(e => qeMap.set(e.ts + '_' + (e.quoteId||''), e));
    fsQE.forEach(e => { const k = e.ts + '_' + (e.quoteId||''); if (!qeMap.has(k)) qeMap.set(k, e); });
    adminData.quoteEvents = [...qeMap.values()].sort((a, b) => (a.ts||0) - (b.ts||0));

    console.log(`📊 Admin analytics loaded from Firestore: ${adminData.searches.length} searches, ${adminData.activityLog.length} activity events`);
  } catch(e) {
    console.warn('Admin analytics Firestore load failed:', e.message);
  }
}

