// =====================================================================
// SUBURB AUTOCOMPLETE + VERIFICATION
// =====================================================================

var _sqmResolvedCluster = null;  // [city, state] once suburb verified
var _sqmResolvedSuburb  = null;  // display suburb name
var _sqmIsRural         = false; // true if resolved via rural fallback
var _sqmRuralClusters   = null;  // [{city, state, distKm, checked}] for multi-cluster rural
var _suburbAutocomplete = null;  // Google Places autocomplete instance
var _suburbDebounce     = null;

function _attachSuburbAutocomplete() {
  const input = document.getElementById('sqm-site-address');
  if (!input) return;
  if (window._placesReady && window.google && window.google.maps && window.google.maps.places) {
    // Google Places available
    if (_suburbAutocomplete) return; // already attached
    _suburbAutocomplete = new google.maps.places.Autocomplete(input, {
      types: ['(regions)'],
      componentRestrictions: { country: 'au' },
      fields: ['name', 'address_components', 'geometry', 'formatted_address']
    });
    _suburbAutocomplete.addListener('place_changed', () => {
      const place = _suburbAutocomplete.getPlace();
      if (!place.address_components) return;
      let suburb = '', state = '', city = '';
      place.address_components.forEach(c => {
        if (c.types.includes('locality') || c.types.includes('sublocality_level_1')) suburb = c.long_name;
        if (c.types.includes('administrative_area_level_1')) state = c.short_name;
        if (c.types.includes('administrative_area_level_2') || c.types.includes('locality')) city = c.long_name;
      });
      const displaySuburb = suburb || place.name;
      // Map state to major city cluster using our known data
      const detected = detectCityFromAddress(displaySuburb + ' ' + state);
      _sqmResolvedCluster = detected || [city || displaySuburb, state];
      _sqmResolvedSuburb  = displaySuburb;
      showSuburbVerified(displaySuburb, state, _sqmResolvedCluster[0]);
      {const _el_sqm_suburb_dropdown=document.getElementById('sqm-suburb-dropdown');if(_el_sqm_suburb_dropdown)_el_sqm_suburb_dropdown.style.display='none';}
    });
  }
  // Manual fallback: input listener
  input.addEventListener('input', () => onSuburbInput(input.value));
}

function onSuburbInput(val) {
  clearTimeout(_suburbDebounce);
  if (!val || val.length < 2) {
    {const _el_sqm_suburb_dropdown=document.getElementById('sqm-suburb-dropdown');if(_el_sqm_suburb_dropdown)_el_sqm_suburb_dropdown.style.display='none';}
    resetSuburbVerification();
    return;
  }
  if (window._placesReady) return; // Google handles it
  _sqmResolvedCluster = null;
  _sqmResolvedSuburb  = null;
  // Manual suburb suggestions — uses _suburbMatches for multi-city support
  _suburbDebounce = setTimeout(() => {
    const q = val.toLowerCase().trim();
    const matches = _suburbMatches(q);
    if (matches.length > 0) {
      renderSuburbDropdown(matches);
    } else {
      // Layer 1 & 2 fallback: check rural map and coords
      const rural = _resolveSuburbToCluster(q);
      if (rural) {
        // Show a single rural option in dropdown
        const dd = document.getElementById('sqm-suburb-dropdown');
        if (dd) {
          const displayName = val.replace(/\b\w/g, c => c.toUpperCase());
          const kmLabel = rural.nearestKm ? ` · ~${rural.nearestKm}km to depot` : '';
          dd.innerHTML = `<div style="padding:.6rem .9rem;cursor:pointer;font-size:.87rem;background:linear-gradient(135deg,#FFF7ED,#FEF3C7);border-left:4px solid #F97316;border-bottom:1px solid #FCD34D"
            onmousedown="selectSuburbSuggestion('${q}','${rural.city}','${rural.state}',true)">
            <div style="display:flex;align-items:center;gap:.6rem">
              <span style="font-size:1.2rem">🏗️</span>
              <div>
                <strong style="color:#92400E;font-size:.9rem">${displayName}</strong>
                <div style="color:#C2410C;font-size:.76rem;font-weight:700;margin-top:.1rem">Rural / Remote Site · Nearest depot: ${rural.city}, ${rural.state}${kmLabel}</div>
                <div style="color:#78350F;font-size:.72rem;margin-top:.1rem">Transport costs will apply — rental companies will include these in their quotes</div>
              </div>
            </div>
          </div>`;
          dd.style.display = 'block';
        }
      } else {
        {const _el_sqm_suburb_dropdown=document.getElementById('sqm-suburb-dropdown');if(_el_sqm_suburb_dropdown)_el_sqm_suburb_dropdown.style.display='none';}
        {const _el_sqm_suburb_unverified=document.getElementById('sqm-suburb-unverified');if(_el_sqm_suburb_unverified)_el_sqm_suburb_unverified.style.display='block';}
        {const _el_sqm_suburb_verified=document.getElementById('sqm-suburb-verified');if(_el_sqm_suburb_verified)_el_sqm_suburb_verified.style.display='none';}
      }
    }
  }, 200);
}

function renderSuburbDropdown(matches) {
  const dd = document.getElementById('sqm-suburb-dropdown');
  if (dd) dd.innerHTML = matches.map(m =>
    `<div style="padding:.5rem .85rem;cursor:pointer;font-size:.87rem;border-bottom:1px solid #f1f5f9;display:flex;align-items:center;gap:.6rem"
      onmousedown="selectSuburbSuggestion('${m.suburb}','${m.city}','${m.state}',false)" >
      <span style="font-size:.95rem">📍</span>
      <div><strong style="color:#1e293b;text-transform:capitalize">${m.suburb}</strong>
        <span style="color:#64748b;font-size:.78rem;margin-left:.35rem">${m.city}, ${m.state}</span></div>
    </div>`
  ).join('');
  dd.style.display = 'block';
}

function selectSuburbSuggestion(suburb, city, state, isRural) {
  const displaySuburb = suburb.replace(/\b\w/g, c => c.toUpperCase());
  document.getElementById('sqm-site-address').value = displaySuburb + (state ? ', ' + state : '');
  _sqmResolvedCluster = [city, state];
  _sqmResolvedSuburb  = displaySuburb;
  _sqmIsRural = !!isRural;
  _sqmRuralClusters = null;

  if (isRural) {
    // Look up actual coordinates for the rural town if available — gives correct distances
    // Falls back to nearest depot centroid if not in RURAL_COORDS
    const suburbKey = suburb.toLowerCase().trim();
    const siteCoords = RURAL_COORDS[suburbKey]
      || (function() {
           // try prefix match in RURAL_COORDS
           const k = Object.keys(RURAL_COORDS).find(function(k) { return suburbKey.startsWith(k) || k.startsWith(suburbKey); });
           return k ? RURAL_COORDS[k] : null;
         })()
      || _getCityCentroid(city); // fallback to nearest depot centroid
    // Compute top 3 nearest depots from actual site location — all pre-ticked
    const clusters = _topNearestDepots(siteCoords, 3);
    _sqmRuralClusters = clusters;
    _renderRuralClusterPicker(displaySuburb, state, clusters);
  } else {
    _hideRuralClusterPicker();
    showSuburbVerified(displaySuburb, state, city, false);
  }
  {const _el_sqm_suburb_dropdown=document.getElementById('sqm-suburb-dropdown');if(_el_sqm_suburb_dropdown)_el_sqm_suburb_dropdown.style.display='none';}
}

function _renderRuralClusterPicker(suburb, state, clusters) {
  // Show the verified badge in orange
  showSuburbVerified(suburb, state, clusters[0] ? clusters[0].city : '', true);
  // Render the cluster picker below the verified badge
  let pickerEl = document.getElementById('sqm-rural-cluster-picker');
  if (!pickerEl) {
    pickerEl = document.createElement('div');
    pickerEl.id = 'sqm-rural-cluster-picker';
    const verifiedEl = document.getElementById('sqm-suburb-verified');
    if (verifiedEl && verifiedEl.parentNode) {
      verifiedEl.parentNode.insertBefore(pickerEl, verifiedEl.nextSibling);
    }
  }
  pickerEl.innerHTML = `
    <div style="margin-top:.6rem;background:linear-gradient(135deg,#FFF7ED,#FFFBEB);border:2px solid #F97316;border-radius:12px;padding:.75rem 1rem">
      <div style="font-weight:800;color:#92400E;font-size:.82rem;margin-bottom:.5rem">
        📡 Send enquiry to rental companies at these depots:
        <span style="font-weight:400;color:#78350F;font-size:.75rem"> — all 3 nearest are ticked. Untick any you don't want to contact</span>
      </div>
      <div style="display:flex;flex-direction:column;gap:.35rem">
        ${clusters.map((c, i) => `
          <label style="display:flex;align-items:center;gap:.6rem;cursor:pointer;padding:.4rem .6rem;background:${c.checked?'rgba(249,115,22,.1)':'#fff'};border:1.5px solid ${c.checked?'#F97316':'#E2E8F0'};border-radius:8px;transition:all .15s" id="sqm-cluster-label-${i}">
            <input type="checkbox" ${c.checked?'checked':''} data-city="${c.city}" data-state="${c.state}"
              onchange="_onClusterToggle(${i})"
              style="width:15px;height:15px;accent-color:#F97316;flex-shrink:0">
            <div style="flex:1">
              <span style="font-weight:800;color:#1E293B;font-size:.84rem">${c.city}</span>
              <span style="color:#64748B;font-size:.77rem;margin-left:.3rem">${c.state}</span>
              <span style="color:#92400E;font-size:.75rem;font-weight:700;margin-left:.5rem">~${c.distKm.toLocaleString()} km road (approx)</span>
              ${i===0?'<span style="background:#FEF3C7;color:#92400E;border-radius:20px;font-size:.68rem;font-weight:800;padding:.05rem .4rem;margin-left:.4rem">nearest</span>':''}
            </div>
          </label>`).join('')}
      </div>
      <div style="margin-top:.5rem;font-size:.72rem;color:#78350F;line-height:1.5">
        💡 All 3 nearest depots are selected. Untick any you don't want to contact. Rental companies will quote including transport costs to your site.
      </div>
    </div>`;
  pickerEl.style.display = 'block';
}

function _onClusterToggle(idx) {
  if (!_sqmRuralClusters) return;
  const cb = document.querySelector(`#sqm-cluster-label-${idx} input`);
  if (!cb) return;
  _sqmRuralClusters[idx].checked = cb.checked;
  // Update label style
  const lbl = document.getElementById('sqm-cluster-label-' + idx);
  if (lbl) {
    lbl.style.background = cb.checked ? 'rgba(249,115,22,.1)' : '#fff';
    lbl.style.border = '1.5px solid ' + (cb.checked ? '#F97316' : '#E2E8F0');
  }
  // Keep _sqmResolvedCluster pointing to first checked depot
  const first = _sqmRuralClusters.find(c => c.checked);
  if (first) _sqmResolvedCluster = [first.city, first.state];
}

function _hideRuralClusterPicker() {
  const el = document.getElementById('sqm-rural-cluster-picker');
  if (el) el.style.display = 'none';
}


function showSuburbVerified(suburb, state, cluster, isRural) {
  const verifiedEl = document.getElementById('sqm-suburb-verified');
  const tickEl     = document.getElementById('sqm-suburb-tick');
  const clusterEl  = document.getElementById('sqm-cluster-badge');

  if (verifiedEl) {
    if (isRural) {
      // ── Rural / Remote — vivid orange ────────────────────────────────────
      verifiedEl.style.cssText = 'display:inline-flex;margin-top:.4rem;align-items:center;gap:.4rem;background:linear-gradient(135deg,#FFF7ED,#FEF3C7);border:2px solid #F97316;border-radius:12px;padding:.4rem 1rem .4rem .75rem;font-size:.83rem;font-weight:800;color:#C2410C;width:fit-content;box-shadow:0 2px 8px rgba(249,115,22,.2)';
      if (tickEl) tickEl.textContent = '🏗️';
      if (clusterEl) {
        clusterEl.textContent = ' · Rural/Remote — nearest depot: ' + cluster;
        clusterEl.style.cssText = 'font-weight:700;color:#92400E;font-size:.78rem';
      }
    } else {
      // ── Metro / suburban — green ──────────────────────────────────────────
      verifiedEl.style.cssText = 'display:inline-flex;margin-top:.4rem;align-items:center;gap:.4rem;background:#F0FDF4;border:1px solid #86EFAC;border-radius:20px;padding:.3rem .8rem;font-size:.82rem;font-weight:700;color:#15803D;width:fit-content';
      if (tickEl) tickEl.textContent = '✅';
      if (clusterEl) {
        clusterEl.textContent = '📡 ' + cluster + ' cluster';
        clusterEl.style.cssText = 'font-weight:400;color:#64748B;font-size:.76rem';
      }
    }
    verifiedEl.style.display = 'inline-flex';
  }
  {const _el_sqm_suburb_unverified=document.getElementById('sqm-suburb-unverified');if(_el_sqm_suburb_unverified)_el_sqm_suburb_unverified.style.display='none';}

  const nameEl = document.getElementById('sqm-suburb-name');
  const stEl   = document.getElementById('sqm-suburb-state');
  if (nameEl) nameEl.textContent = suburb;
  if (stEl)   stEl.textContent   = state;

  // Auto-fill city + state fields
  const cityInput  = document.getElementById('sqm-city-input');
  const stateInput = document.getElementById('sqm-state-input');
  const cityRow    = document.getElementById('sqm-city-state-row');
  if (cityInput)  cityInput.value  = cluster || '';
  if (stateInput) stateInput.value = state   || '';
  if (cityRow)    cityRow.style.display = (cluster || state) ? 'flex' : 'none';
}

function resetSuburbVerification() {
  _sqmResolvedCluster = null;
  _sqmResolvedSuburb  = null;
  _sqmIsRural         = false;
  _sqmRuralClusters   = null;
  {const _el_sqm_suburb_verified=document.getElementById('sqm-suburb-verified');if(_el_sqm_suburb_verified)_el_sqm_suburb_verified.style.display='none';}
  {const _el_sqm_suburb_unverified=document.getElementById('sqm-suburb-unverified');if(_el_sqm_suburb_unverified)_el_sqm_suburb_unverified.style.display='none';}
  _hideRuralClusterPicker();
  const cityInput  = document.getElementById('sqm-city-input');
  const stateInput = document.getElementById('sqm-state-input');
  const cityRow    = document.getElementById('sqm-city-state-row');
  if (cityInput)  cityInput.value  = '';
  if (stateInput) stateInput.value = '';
  if (cityRow)    cityRow.style.display = 'none';
}

function clearSuburbVerification() {
  document.getElementById('sqm-site-address').value = '';
  resetSuburbVerification();
  document.getElementById('sqm-site-address').focus();
}

function onSuburbBlur() {
  // Small delay so clicks on dropdown register first
  setTimeout(() => {
    {const _el_sqm_suburb_dropdown=document.getElementById('sqm-suburb-dropdown');if(_el_sqm_suburb_dropdown)_el_sqm_suburb_dropdown.style.display='none';}
    // If not verified yet but has text, try detecting from text
    if (!_sqmResolvedCluster) {
      const val = document.getElementById('sqm-site-address').value.trim();
      if (val) {
        const detected = detectCityFromAddress(val);
        if (detected) {
          _sqmResolvedCluster = detected;
          _sqmResolvedSuburb  = val.split(',')[0].trim();
          showSuburbVerified(_sqmResolvedSuburb, detected[1], detected[0]);
        } else {
          {const _el_sqm_suburb_unverified=document.getElementById('sqm-suburb-unverified');if(_el_sqm_suburb_unverified)_el_sqm_suburb_unverified.style.display='block';}
          {const _el_sqm_suburb_verified=document.getElementById('sqm-suburb-verified');if(_el_sqm_suburb_verified)_el_sqm_suburb_verified.style.display='none';}
        }
      }
    }
  }, 200);
}

