// ── Unread quote tracking for rental users ──────────────────
function _seenKey() {
  return 'noyo_seen_quotes_' + (currentUser ? currentUser.email : 'anon');
}
function getSeenQuoteIds() {
  try { return new Set(JSON.parse(localStorage.getItem(_seenKey()) || '[]')); } catch(e) { return new Set(); }
}
function _seenMQKey() { return 'noyo_seen_mq_' + (currentUser?.email||''); }
function getSeenMyQuoteIds() {
  try { return new Set(JSON.parse(localStorage.getItem(_seenMQKey()) || '[]')); } catch(e) { return new Set(); }
}

// ── Load notification state from Firestore on login ───────────
async function _loadNotificationStateFromFirestore() {
  if (!_fbDb || !currentUser || !currentUser.uid) return;
  try {
    const snap = await _fbDb.collection('notification_state').doc(currentUser.uid).get();
    if (snap.exists) {
      const data = snap.data();
      if (data.seenQuoteIds)   try { localStorage.setItem(_seenKey(),    JSON.stringify(data.seenQuoteIds));   } catch(e) {}
      if (data.seenMyQuoteIds) try { localStorage.setItem(_seenMQKey(),  JSON.stringify(data.seenMyQuoteIds)); } catch(e) {}
    }
  } catch(e) { console.warn('Notification state load failed:', e.message); }
}

// ── RENTAL: mark all QR as seen when tab opened ──
function markQuotesRead() {
  if (!currentUser || currentUser.role !== 'rental') return;
  const allIds = quoteInbox.map(r => r.id);
  try { localStorage.setItem(_seenKey(), JSON.stringify(allIds)); } catch(e) {}
  // Persist to Firestore
  if (_fbDb && currentUser.uid) {
    _fbDb.collection('notification_state').doc(currentUser.uid).set(
      { seenQuoteIds: allIds, updatedAt: firebase.firestore.FieldValue.serverTimestamp() },
      { merge: true }
    ).catch(() => {});
  }
  updateQRUnreadBadge();
}

// ── CUSTOMER: mark My Quotes as seen when tab opened ──
function markMyQuotesRead() {
  if (!currentUser || currentUser.role !== 'customer') return;
  const myEmail = currentUser.email.toLowerCase();
  const allIds = quoteInbox.filter(r => (r.email||'').toLowerCase() === myEmail).map(r => r.id);
  try { localStorage.setItem(_seenMQKey(), JSON.stringify(allIds)); } catch(e) {}
  // Persist to Firestore
  if (_fbDb && currentUser.uid) {
    _fbDb.collection('notification_state').doc(currentUser.uid).set(
      { seenMyQuoteIds: allIds, updatedAt: firebase.firestore.FieldValue.serverTimestamp() },
      { merge: true }
    ).catch(() => {});
  }
  updateMQUnreadBadge();
}

// ── RENTAL COMPANY: unread QR badge ──
function updateQRUnreadBadge() {
  const badge = document.getElementById('qr-unread-badge');
  if (!badge || !currentUser || currentUser.role !== 'rental') return;
  const seen = getSeenQuoteIds();
  const myName = currentUser?.name;
  // Count: new leads not yet seen, OR accepted quotes not yet actioned
  const unread = quoteInbox.filter(r => !seen.has(r.id)).length;
  // Also count: quotes where I've responded but customer accepted mine and I haven't "seen" it
  const myAccepted = quoteInbox.filter(r =>
    r.acceptedBy === myName && !seen.has(r.id + '_acc')
  ).length;
  const total = unread + myAccepted;
  if (total > 0) {
    badge.textContent = total;
    badge.style.display = 'inline';
  } else {
    badge.style.display = 'none';
  }
}

// ── CUSTOMER: unactioned quotes badge ──
function updateMQUnreadBadge() {
  const badge = document.getElementById('mq-unread-badge');
  if (!badge || !currentUser || currentUser.role !== 'customer') return;
  const myEmail = currentUser.email.toLowerCase();
  const seen = getSeenMyQuoteIds();
  const myReqs = quoteInbox.filter(r => (r.email||'').toLowerCase() === myEmail);
  // Count: requests that have NEW responses since last seen, and aren't yet accepted/rejected
  let unactioned = 0;
  myReqs.forEach(req => {
    const hasResponses = (req.responses||[]).some(rsp => rsp.company);
    const isActioned = !!req.acceptedBy;
    const isSeen = seen.has(req.id);
    if (hasResponses && !isActioned && !isSeen) unactioned++;
  });
  if (unactioned > 0) {
    badge.textContent = unactioned;
    badge.style.display = 'inline';
  } else {
    badge.style.display = 'none';
  }
}

function renderQuoteRequests() {
  const list    = document.getElementById('qr-list');
  const badges  = document.getElementById('qr-summary-badges');
  if (!list || !badges) return;

  const userEmail = currentUser ? currentUser.email : null;
  if (!userEmail) {
    list.innerHTML = '<div style="padding:2rem;text-align:center;color:#94A3B8">Please log in to view your quote requests.</div>';
    return;
  }

  const now0 = Date.now();
  // Get active sort from state
  const qrSort = window._qrSort || 'expiry';

  // Resolve this user's company for location-based filtering
  const _qrUserCompany = _resolveUserCompany();

  const rawLeads = [...quoteInbox]
    .filter(req => {
      // Never show own enquiries
      if ((req.email||'').toLowerCase() === userEmail) return false;
      // Filter by service area if we have depot data
      if (_qrUserCompany) return enquiryVisibleToCompany(req, _qrUserCompany);
      return true;
    });

  // Sort logic
  function sortLeads(leads, mode) {
    return [...leads].sort((a, b) => {
      if (mode === 'expiry') {
        // Soonest expiry first; expired pushed to bottom
        const aLeft = a.expires ? a.expires - now0 : -Infinity;
        const bLeft = b.expires ? b.expires - now0 : -Infinity;
        const aExp = aLeft <= 0, bExp = bLeft <= 0;
        if (aExp && !bExp) return 1;
        if (!aExp && bExp) return -1;
        if (!aExp && !bExp) return aLeft - bLeft; // soonest first
        return b.ts - a.ts; // both expired: newest first
      }
      if (mode === 'newest')   return b.ts - a.ts;
      if (mode === 'oldest')   return a.ts - b.ts;
      if (mode === 'hiredate') {
        const aD = a.date ? new Date(a.date).getTime() : 0;
        const bD = b.date ? new Date(b.date).getTime() : 0;
        return aD - bD; // soonest hire start first
      }
      if (mode === 'unquoted') {
        // Unquoted active leads first, then quoted, then expired
        const myN = currentUser?.name;
        const aQ = (a.responses||[]).some(r => r.company === myN);
        const bQ = (b.responses||[]).some(r => r.company === myN);
        const aE = a.expires <= now0, bE = b.expires <= now0;
        if (!aQ && !aE && (bQ || bE)) return -1;
        if ((aQ || aE) && !bQ && !bE) return 1;
        return (a.expires||0) - (b.expires||0);
      }
      return b.ts - a.ts;
    });
  }

  const myLeads = sortLeads(rawLeads, qrSort);
  const total     = myLeads.length;
  const myResponded = myLeads.filter(r => (r.responses||[]).some(rsp => rsp.company === currentUser?.name)).length;
  const active    = myLeads.filter(r => r.expires > now0).length;

  const myWon      = myLeads.filter(r => r.acceptedBy === currentUser?.name).length;
  const myLost     = myLeads.filter(r => r.acceptedBy && r.acceptedBy !== currentUser?.name).length;
  const urgent     = myLeads.filter(r => !r.responded && r.expires && workingMinsRemaining(Date.now(), r.expires, r.state) < 120 && workingMinsRemaining(Date.now(), r.expires, r.state) > 0).length;
  const unquotedOpen = myLeads.filter(r => !myLeads.find(x=>x===r) || true).filter(r => {
    const hasMyQ = (r.responses||[]).some(rsp => rsp.company === currentUser?.name);
    return !hasMyQ && !r.acceptedBy && r.expires && Date.now() < r.expires;
  }).length;

  const sortOptions = [
    { val:'expiry',   label:'⏱ Expiring Soon' },
    { val:'hiredate', label:'📅 Hire Date' },
    { val:'unquoted', label:'🆕 Unquoted First' },
    { val:'newest',   label:'🕐 Newest First' },
    { val:'oldest',   label:'🕐 Oldest First' },
  ];

  badges.innerHTML = `
    <span style="background:#EFF6FF;color:#1D4ED8;font-size:.78rem;font-weight:700;padding:.3rem .75rem;border-radius:20px;border:1px solid #BFDBFE">${total} Total</span>
    ${unquotedOpen > 0 ? `<span style="background:#EFF6FF;color:#0052CC;font-size:.78rem;font-weight:700;padding:.3rem .75rem;border-radius:20px;border:2px solid #0052CC">🆕 ${unquotedOpen} New</span>` : ''}
    ${urgent > 0 ? `<span style="background:#FEF2F2;color:#DC2626;font-size:.78rem;font-weight:700;padding:.3rem .75rem;border-radius:20px;border:2px solid #EF4444">🚨 ${urgent} Urgent</span>` : ''}
    ${active > 0 ? `<span style="background:#FFFDF0;color:#B45309;font-size:.78rem;font-weight:700;padding:.3rem .75rem;border-radius:20px;border:1.5px solid #FCD34D">✓ ${myResponded} Quoted</span>` : ''}
    ${myWon > 0 ? `<span style="background:#F0FDF4;color:#166534;font-size:.78rem;font-weight:700;padding:.3rem .75rem;border-radius:20px;border:1.5px solid #86EFAC">🏆 ${myWon} Won</span>` : ''}
    ${myLost > 0 ? `<span style="background:#F8FAFC;color:#94A3B8;font-size:.78rem;font-weight:700;padding:.3rem .75rem;border-radius:20px;border:1px solid #E2E8F0">✗ ${myLost} Lost</span>` : ''}
    <div style="display:flex;align-items:center;gap:.4rem;flex-wrap:wrap;margin-top:.3rem;font-size:.7rem;color:#94A3B8;font-weight:600">
      <span style="display:inline-flex;align-items:center;gap:.3rem"><span style="width:10px;height:10px;border-radius:2px;background:#0052CC;display:inline-block"></span>New</span>
      <span style="display:inline-flex;align-items:center;gap:.3rem"><span style="width:10px;height:10px;border-radius:2px;background:#EF4444;display:inline-block"></span>Urgent</span>
      <span style="display:inline-flex;align-items:center;gap:.3rem"><span style="width:10px;height:10px;border-radius:2px;background:#F59E0B;display:inline-block"></span>Quoted</span>
      <span style="display:inline-flex;align-items:center;gap:.3rem"><span style="width:10px;height:10px;border-radius:2px;background:#16A34A;display:inline-block"></span>Won</span>
      <span style="display:inline-flex;align-items:center;gap:.3rem"><span style="width:10px;height:10px;border-radius:2px;background:#CBD5E1;display:inline-block"></span>Closed</span>
    </div>
    <div style="margin-left:auto;display:flex;align-items:center;gap:.35rem;flex-wrap:wrap">
      <span style="font-size:.74rem;font-weight:700;color:#64748B">Sort:</span>
      ${sortOptions.map(o => `<button onclick="window._qrSort='${o.val}';renderQuoteRequests()" style="padding:.22rem .65rem;border-radius:20px;font-family:'Nunito',sans-serif;font-weight:700;font-size:.74rem;cursor:pointer;border:1.5px solid ${qrSort===o.val?'#0052CC':'#E2E8F0'};background:${qrSort===o.val?'#EFF6FF':'#F8FAFC'};color:${qrSort===o.val?'#0052CC':'#64748B'};transition:all .15s">${o.label}</button>`).join('')}
    </div>
  `;

  if (myLeads.length === 0) {
    list.innerHTML = `<div style="background:#F8FAFC;border:1.5px dashed #CBD5E1;border-radius:14px;padding:2.5rem;text-align:center">
      <div style="font-size:2.5rem;margin-bottom:.75rem">📭</div>
      <div style="font-weight:700;color:#334155;font-size:1rem;margin-bottom:.35rem">No enquiries yet</div>
    </div>`;
    return;
  }

  list.innerHTML = myLeads.map(req => {
    const now    = Date.now();
    const msLeft = req.expires ? req.expires - now : 0;
    const expired = msLeft <= 0;
    const myResp = (req.responses||[]).find(r => r.company === currentUser?.name);
    const sentDate = req.ts ? new Date(req.ts) : null;
    const sentStr  = sentDate
      ? sentDate.toLocaleDateString('en-AU',{day:'2-digit',month:'short',year:'numeric'}) + ' at ' + sentDate.toLocaleTimeString('en-AU',{hour:'2-digit',minute:'2-digit'})
      : '—';

    // First name only
    const firstName = (req.customer || '').split(' ')[0] || 'Customer';
    const suburb    = req.suburb || (req.siteAddress||'').split(',')[0] || '—';
    const state     = req.state || '';
    const hireStart = req.date || '—';
    const durLbl    = DUR_LABEL[req.machines?.[0]?.duration || '1-day'] || '1 day';

    let statusBadge;
    if (myResp) {
      statusBadge = `<span style="background:#DCFCE7;color:#166534;font-size:.74rem;font-weight:800;padding:.22rem .65rem;border-radius:20px">✓ Quoted — $${(myResp.grandTotal||0).toFixed(2)}</span>`;
    } else if (expired) {
      statusBadge = `<span style="background:#F1F5F9;color:#94A3B8;font-size:.74rem;font-weight:800;padding:.22rem .65rem;border-radius:20px">Closed</span>`;
    } else {
      const wMins = workingMinsRemaining(now, req.expires, req.state);
      const wHrs = Math.floor(wMins/60), wMin = wMins%60;
      const urgent = wMins < 120;
      statusBadge = `<span style="background:${urgent?'#FEF2F2':'#FFFBEB'};color:${urgent?'#B91C1C':'#B45309'};font-size:.74rem;font-weight:800;padding:.22rem .65rem;border-radius:20px">⏱ ${wHrs}h ${wMin}m left</span>`;
    }

    const machineList = (req.machines||[]).map(m => `<span style="display:inline-flex;align-items:center;gap:.3rem;background:#F1F5F9;color:#334155;font-size:.78rem;font-weight:600;padding:.18rem .55rem;border-radius:7px">${m.emoji||'🏗️'} ${m.name}</span>`).join(' ');

    const windowLabel = req.responseWindowHours===2 ? '🚨 2h' : req.responseWindowHours===4 ? '⚡ 4h' : '📋 8h';

    const quoteBtn = (!myResp && !expired)
      ? `<button onclick="openRespondModal('${req.id}')" style="background:#0052CC;color:#fff;border:none;border-radius:10px;padding:.6rem 1.4rem;font-family:'Nunito',sans-serif;font-weight:800;font-size:.88rem;cursor:pointer">📋 Quote Now</button>`
      : myResp && !expired
        ? `<div style="display:flex;gap:.5rem">
             <button onclick="openViewQuoteModal('${req.id}')" style="background:#F0FDF4;color:#166534;border:1.5px solid #86EFAC;border-radius:10px;padding:.55rem 1rem;font-family:'Nunito',sans-serif;font-weight:800;font-size:.85rem;cursor:pointer">👁️ View Quote</button>
             <button onclick="openRespondModal('${req.id}')" style="background:#E2E8F0;color:#475569;border:none;border-radius:10px;padding:.55rem 1rem;font-family:'Nunito',sans-serif;font-weight:800;font-size:.85rem;cursor:pointer">✏️ Edit Quote</button>
           </div>`
        : myResp && expired
          ? `<div style="display:flex;gap:.5rem;align-items:center">
               <span style="background:#DCFCE7;color:#166534;font-size:.78rem;font-weight:800;padding:.3rem .8rem;border-radius:20px">✓ Quoted — $${(myResp.grandTotal||0).toFixed(2)}</span>
               <button onclick="openViewQuoteModal('${req.id}')" style="background:#F8FAFC;color:#64748B;border:1px solid #E2E8F0;border-radius:10px;padding:.4rem .9rem;font-family:'Nunito',sans-serif;font-weight:700;font-size:.82rem;cursor:pointer">👁️ View</button>
             </div>`
          : '';

    return `
    <div style="background:${
      req.acceptedBy === currentUser?.name ? '#F0FDF4'
      : req.acceptedBy                     ? '#F8FAFC'
      : myResp && !expired                 ? '#FFFDF0'
      : myResp && expired                  ? '#F8FAFC'
      : expired                            ? '#F9FAFB'
      : (() => { const _wm = workingMinsRemaining(now, req.expires, req.state); return _wm < 120 ? '#FFF5F5' : '#F0F7FF'; })()
    };border:1.5px solid ${
      req.acceptedBy === currentUser?.name ? '#86EFAC'
      : req.acceptedBy                     ? '#E2E8F0'
      : myResp && !expired                 ? '#FCD34D'
      : myResp && expired                  ? '#E2E8F0'
      : expired                            ? '#E2E8F0'
      : (() => { const _wm = workingMinsRemaining(now, req.expires, req.state); return _wm < 120 ? '#FCA5A5' : '#BFDBFE'; })()
    };border-left:5px solid ${
      req.acceptedBy === currentUser?.name ? '#16A34A'
      : req.acceptedBy                     ? '#CBD5E1'
      : myResp && !expired                 ? '#F59E0B'
      : myResp && expired                  ? '#CBD5E1'
      : expired                            ? '#CBD5E1'
      : (() => { const _wm = workingMinsRemaining(now, req.expires, req.state); return _wm < 120 ? '#EF4444' : '#0052CC'; })()
    };border-radius:14px;padding:1rem 1rem 1rem 1.1rem;box-shadow:0 1px 4px rgba(0,0,0,.05)">
      <div style="display:flex;align-items:flex-start;justify-content:space-between;gap:.8rem;flex-wrap:wrap;margin-bottom:.7rem">
        <div>
          <div style="font-weight:900;color:#0F172A;font-size:.95rem">👤 ${firstName}</div>
          <div style="font-size:.8rem;color:#64748B;margin-top:.2rem">📍 ${suburb}${state?', '+state:''} &nbsp;·&nbsp; 📅 Hire start: ${hireStart} &nbsp;·&nbsp; ⏳ ${durLbl} &nbsp;·&nbsp; ${windowLabel}${req.isRural ? ` &nbsp;·&nbsp; <span style="background:linear-gradient(135deg,#FFF7ED,#FEF3C7);color:#C2410C;border:2px solid #F97316;font-size:.72rem;font-weight:800;padding:.15rem .55rem;border-radius:12px">🏗️ Rural/Remote</span>` : ''}</div>
          <div style="font-size:.75rem;color:#94A3B8;margin-top:.1rem">Sent: ${sentStr}</div>
        </div>
        <div style="display:flex;align-items:center;gap:.5rem;flex-wrap:wrap">
          ${req.acceptedBy && req.acceptedBy === currentUser?.name ? '<span style="background:#DCFCE7;color:#166534;font-size:.74rem;font-weight:800;padding:.22rem .65rem;border-radius:20px">🏆 Accepted by Customer</span>' : ''}
          ${req.acceptedBy && req.acceptedBy !== currentUser?.name ? '<span style="background:#F1F5F9;color:#94A3B8;font-size:.74rem;font-weight:800;padding:.22rem .65rem;border-radius:20px">✗ Another quote accepted</span>' : ''}
          ${!req.acceptedBy ? statusBadge : ''}
        </div>
      </div>
      <div style="display:flex;flex-wrap:wrap;gap:.3rem;margin-bottom:.8rem">${machineList}</div>
      ${(() => {
        // Customer acceptance window for this rental company
        if (!myResp || req.acceptedBy) return '';
        const _aDeadline = req.customerAcceptExpires;
        if (!_aDeadline) return '';
        const _now4 = Date.now();
        const _aExp = _now4 > _aDeadline;
        if (_aExp) {
          return '<div style="margin-bottom:.6rem;padding:.35rem .75rem;background:#F8FAFC;border:1px solid #E2E8F0;border-radius:8px;font-size:.76rem;color:#94A3B8;font-weight:700">🔒 Customer acceptance window closed</div>';
        }
        const _aMins = workingMinsRemaining(_now4, _aDeadline, req.state);
        const _aLabel = _aMins > 60 ? Math.floor(_aMins/60)+'h '+(_aMins%60)+'m' : _aMins+'m';
        const _urg = _aMins < 60;
        const _bg = _urg ? '#FEF2F2' : '#FFFBEB';
        const _bdr = _urg ? '#FCA5A5' : '#FCD34D';
        const _clr = _urg ? '#DC2626' : '#B45309';
        const _ico = _urg ? '🚨' : '⏱️';
        return '<div style="margin-bottom:.6rem;padding:.35rem .75rem;background:'+_bg+';border:1px solid '+_bdr+';border-radius:8px;font-size:.76rem;color:'+_clr+';font-weight:700">'+_ico+' Customer has <strong>'+_aLabel+'</strong> to accept your quote</div>';
      })()}
      ${myResp ? (() => {
        const _nmTid = 'nm-' + (req.id||'x').replace(/[^a-z0-9]/gi,'') + '__' + encodeURIComponent(currentUser?.name||'co') + '__company';
        return _nmBuildThread(req.id, currentUser?.name||'', 'company', _nmTid, true);
      })() : ''}
      ${quoteBtn}
    </div>`;
  }).join('');
  setTimeout(nmHydrateAll, 0);
}

function markQrResponded(reqId) {
  const req = quoteInbox.find(r => r.id === reqId);
  if (!req) return;
  req.responded = true;
  saveInbox();
  renderQuoteRequests();
  renderQuoteInbox();
  showToast('✅ Marked as responded', '#166534');
}

// ═══════════════════════════════════════════════════════════════
// FIREBASE AUTH STATE + POLLING
// ═══════════════════════════════════════════════════════════════

// ── Auth persistence: restore session on page reload ─────────
_fbAuth.onAuthStateChanged(async (fbUser) => {
  if (fbUser && !currentUser) {
    // User is signed in but app state was reset (page refresh)
    try {
      const profile = await _fbLoadUserProfile(fbUser.uid);
      const role = profile.role || 'customer';
      const name = profile.fullName || fbUser.email.split('@')[0];

      if (['rental','staff','manager','admin'].includes(role)) {
        const rp = await _fbLoadRentalProfile(fbUser.uid);
        if (rp) {
          _userProfileCache[fbUser.uid] = { ..._userProfileCache[fbUser.uid], ...rp };
          const rcEntry = {
            id: fbUser.uid, name: rp.companyName || name, email: fbUser.email,
            phone: rp.phone || '', address: rp.address || '',
            baseCity: rp.city || '', serviceRadiusKm: rp.serviceRadiusKm || 75,
            cities: [rp.city || ''], sectors: rp.sectors || [],
            machines: (rp.sectors||[]).join(', '), active: rp.active !== false,
            ruralOptIn: rp.ruralOptIn || false, ruralRadiusKm: rp.ruralRadiusKm || 0
          };
          const existIdx = RENTAL_COMPANIES.findIndex(c => c.email === fbUser.email);
          if (existIdx > -1) RENTAL_COMPANIES[existIdx] = { ...RENTAL_COMPANIES[existIdx], ...rcEntry };
          else RENTAL_COMPANIES.push(rcEntry);
        }
      }
      loginSuccess({ name, role, email: fbUser.email, uid: fbUser.uid });
    } catch(e) {
      console.warn('Auth state restore failed:', e.message);
    }
  }
});

// Show Firebase status after page loads
window.addEventListener('load', () => {
  setTimeout(_showFirebaseStatus, 1500);
});

// Poll Firebase every 30 seconds for new quotes/responses
setInterval(async () => {
  if (!currentUser || !currentUser.uid) return;
  try {
    const prev = JSON.stringify(quoteInbox);
    await loadInboxFromFirebase();
    const curr = JSON.stringify(quoteInbox);
    if (prev !== curr) {
      // Data changed — refresh whichever view is active
      const myQ  = document.getElementById('view-my-quotes');
      const qReq = document.getElementById('view-quote-requests');
      const stf  = document.getElementById('view-internal');
      if (myQ  && myQ.classList.contains('active'))  renderMyQuotes();
      if (qReq && qReq.classList.contains('active')) renderQuoteRequests();
      if (stf  && stf.classList.contains('active'))  renderQuoteInbox();
      updateQRUnreadBadge();
    }
  } catch(e) {}
}, 30000);




// ═══════════════════════════════════════════════════════════════
// NOYO SECURE MESSAGING
// Unlocked only after a quote has been exchanged. Messages are
// stored locally keyed by reqId + company slug. Both parties
// communicate through the platform to protect Noyo's role.
// ═══════════════════════════════════════════════════════════════

function _nmKey(reqId, company) {
  return 'noyo_msg_' + reqId + '_' + (company||'').replace(/[^a-z0-9]/gi,'-').toLowerCase();
}

// ── Messages: Firestore PRIMARY, localStorage cache ───────────
function _nmLoad(reqId, company) {
  // Return from localStorage cache immediately, Firestore sync happens async
  try { return JSON.parse(localStorage.getItem(_nmKey(reqId, company)) || '[]'); } catch(e) { return []; }
}

function _nmSave(reqId, company, msgs) {
  // Save to localStorage cache immediately
  try { localStorage.setItem(_nmKey(reqId, company), JSON.stringify(msgs)); } catch(e) {}
  // Save to Firestore persistently
  if (_fbDb) {
    const docId = reqId + '_' + (company||'').replace(/[^a-z0-9]/gi,'-').toLowerCase();
    _fbDb.collection('messages').doc(docId).set({
      reqId, company, messages: msgs,
      updatedAt: firebase.firestore.FieldValue.serverTimestamp()
    }, { merge: true }).catch(e => console.warn('Message save to Firestore failed:', e.message));
  }
}

// Load messages from Firestore and update cache + UI
function _nmLoadFromFirestore(reqId, company, callbackFn) {
  if (!_fbDb) return;
  const docId = reqId + '_' + (company||'').replace(/[^a-z0-9]/gi,'-').toLowerCase();
  _fbDb.collection('messages').doc(docId).get().then(snap => {
    if (snap.exists && Array.isArray(snap.data().messages)) {
      const msgs = snap.data().messages;
      try { localStorage.setItem(_nmKey(reqId, company), JSON.stringify(msgs)); } catch(e) {}
      if (typeof callbackFn === 'function') callbackFn(msgs);
    }
  }).catch(e => console.warn('Message load from Firestore failed:', e.message));
}

function _nmUnreadCount(reqId, company, myRole) {
  const msgs = _nmLoad(reqId, company);
  const otherRole = myRole === 'customer' ? 'company' : 'customer';
  const seenKey = 'noyo_msg_seen_' + reqId + '_' + (company||'').replace(/[^a-z0-9]/gi,'-').toLowerCase() + '_' + myRole;
  const lastSeen = parseInt(localStorage.getItem(seenKey) || '0', 10);
  return msgs.filter(m => m.from === otherRole && m.ts > lastSeen).length;
}

function _nmMarkSeen(reqId, company, myRole) {
  const seenKey = 'noyo_msg_seen_' + reqId + '_' + (company||'').replace(/[^a-z0-9]/gi,'-').toLowerCase() + '_' + myRole;
  try { localStorage.setItem(seenKey, String(Date.now())); } catch(e) {}
  // Persist seen state to Firestore so it's consistent across devices
  if (_fbDb && currentUser && currentUser.uid) {
    const docId = 'seen_' + currentUser.uid;
    const fieldKey = reqId + '_' + (company||'').replace(/[^a-z0-9]/gi,'-').toLowerCase() + '_' + myRole;
    _fbDb.collection('notification_state').doc(docId).set(
      { [fieldKey]: Date.now(), updatedAt: firebase.firestore.FieldValue.serverTimestamp() },
      { merge: true }
    ).catch(() => {});
  }
}

function nmToggle(reqId, company, myRole, threadId) {
  const body = document.getElementById(threadId + '-body');
  const tog  = document.getElementById(threadId + '-tog');
  if (!body) return;
  const isOpen = body.classList.contains('open');
  body.classList.toggle('open', !isOpen);
  if (tog) tog.textContent = isOpen ? '▼ Open' : '▲ Close';
  if (!isOpen) {
    _nmMarkSeen(reqId, company, myRole);
    _nmRefreshBadge(reqId, company, myRole, threadId);
    const inp = document.getElementById(threadId + '-inp');
    if (inp) setTimeout(() => inp.focus(), 80);
  }
}

function _nmRefreshBadge(reqId, company, myRole, threadId) {
  const badge = document.getElementById(threadId + '-badge');
  const cnt = _nmUnreadCount(reqId, company, myRole);
  if (badge) { badge.textContent = cnt; badge.style.display = cnt > 0 ? 'inline' : 'none'; }
}

function nmSend(reqId, company, myRole, threadId) {
  const inp = document.getElementById(threadId + '-inp');
  if (!inp) return;
  const text = inp.value.trim();
  if (!text) return;

  const msgs = _nmLoad(reqId, company);
  msgs.push({ from: myRole, text, ts: Date.now() });
  _nmSave(reqId, company, msgs);
  inp.value = '';
  inp.style.height = 'auto';

  // Re-render just the message list
  _nmRenderMsgs(reqId, company, myRole, threadId);
  _nmMarkSeen(reqId, company, myRole);
  showToast('💬 Message sent securely via Noyo', '#0052CC');
}

function _nmRenderMsgs(reqId, company, myRole, threadId) {
  const listEl = document.getElementById(threadId + '-msgs');
  if (!listEl) return;
  const msgs = _nmLoad(reqId, company);
  if (msgs.length === 0) {
    listEl.innerHTML = '<div style="font-size:.78rem;color:#94A3B8;text-align:center;padding:.5rem 0">No messages yet. Start the conversation below.</div>';
    return;
  }
  listEl.innerHTML = msgs.map(m => {
    const isMine = m.from === myRole;
    const label  = isMine ? 'You' : (myRole === 'customer' ? company : 'Customer');
    const time   = new Date(m.ts).toLocaleString('en-AU',{day:'2-digit',month:'short',hour:'2-digit',minute:'2-digit'});
    return `<div class="nm-msg ${isMine?'sent':'recv'}">
      <div class="nm-bubble">${m.text.replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/\n/g,'<br>')}</div>
      <div class="nm-meta">${label} · ${time}</div>
    </div>`;
  }).join('');
  // Scroll to bottom
  setTimeout(() => { listEl.scrollTop = listEl.scrollHeight; }, 30);
}

function nmKeyDown(e, reqId, company, myRole, threadId) {
  if (e.key === 'Enter' && !e.shiftKey) {
    e.preventDefault();
    nmSend(reqId, company, myRole, threadId);
  }
}

function _nmBuildThread(reqId, company, myRole, threadId, quoteAccepted) {
  const unread = _nmUnreadCount(reqId, company, myRole);
  const msgs   = _nmLoad(reqId, company);
  const otherLabel = myRole === 'customer' ? company : 'the customer';

  if (!quoteAccepted) {
    // Locked — quote not yet exchanged
    return `<div class="nm-thread">
      <div class="nm-lock">
        🔒 <strong>Messaging unlocked after a quote is submitted.</strong>
        All communication is logged through Noyo to protect both parties.
      </div>
    </div>`;
  }

  const msgCountLabel = msgs.length > 0 ? `${msgs.length} message${msgs.length!==1?'s':''}` : 'No messages yet';

  return `<div class="nm-thread">
    <div class="nm-header" onclick="nmToggle('${reqId}','${encodeURIComponent(company)}','${myRole}','${threadId}')">
      <span style="font-size:1.05rem">💬</span>
      <div>
        <span class="nm-header-title">Secure Message Thread</span>
        <span id="${threadId}-badge" class="nm-badge" style="display:${unread>0?'inline':'none'}">${unread}</span>
        <span class="nm-header-sub"> · ${msgCountLabel}</span>
      </div>
      <span id="${threadId}-tog" style="margin-left:auto;font-size:.72rem;color:#64748B;font-weight:700">▼ Open</span>
    </div>
    <div id="${threadId}-body" class="nm-body">
      <div class="nm-disclaimer">
        🛡️ <strong>All messages are facilitated through Noyo.</strong>
        Please keep all hire arrangements, pricing discussions, and agreements on this platform.
        Do not share personal contact details in this thread.
      </div>
      <div id="${threadId}-msgs" style="display:flex;flex-direction:column;gap:.45rem;max-height:260px;overflow-y:auto;padding-right:.2rem"></div>
      <div class="nm-compose">
        <textarea id="${threadId}-inp" class="nm-input" rows="2"
          placeholder="Message ${otherLabel}…"
          onkeydown="nmKeyDown(event,'${reqId}','${encodeURIComponent(company)}','${myRole}','${threadId}')"
          oninput="this.style.height='auto';this.style.height=this.scrollHeight+'px'"></textarea>
        <button class="nm-send" onclick="nmSend('${reqId}','${encodeURIComponent(company)}','${myRole}','${threadId}')">Send ↑</button>
      </div>
    </div>
  </div>`;
}

// Override nmToggle and nmSend to decode company name
const _nmOrigToggle = nmToggle;
nmToggle = function(reqId, company, myRole, threadId) {
  _nmOrigToggle(decodeURIComponent(reqId), decodeURIComponent(company), myRole, threadId);
};
const _nmOrigSend = nmSend;
nmSend = function(reqId, company, myRole, threadId) {
  _nmOrigSend(decodeURIComponent(reqId), decodeURIComponent(company), myRole, threadId);
};

// Called after rendering to hydrate the message lists for all open/closed threads
function nmHydrateAll() {
  document.querySelectorAll('[id$="-msgs"][id^="nm-"]').forEach(el => {
    const threadId = el.id.replace('-msgs','');
    const parts = threadId.replace('nm-','').split('__');
    if (parts.length < 3) return;
    const reqId   = parts[0];
    const company = decodeURIComponent(parts[1]);
    const myRole  = parts[2];
    _nmRenderMsgs(reqId, company, myRole, threadId);
    _nmRefreshBadge(reqId, company, myRole, threadId);
  });
}

function renderAdminFeedback() {

  const list = document.getElementById('admin-feedback-list');
  if (!list) return;
  const items = JSON.parse(localStorage.getItem('noyo_feedback') || '[]')
    .sort((a,b) => b.ts - a.ts);
  const ratings = JSON.parse(localStorage.getItem('noyo_ratings') || '[]')
    .sort((a,b) => b.ts - a.ts);

  // Update badge
  const badge = document.getElementById('admin-feedback-badge');
  if (badge) {
    const unread = items.filter(i => !i._read).length;
    badge.textContent = unread;
    badge.style.display = unread > 0 ? 'inline' : 'none';
  }

  if (items.length === 0 && ratings.length === 0) {
    list.innerHTML = '<div style="color:#94A3B8;text-align:center;padding:2rem">No feedback yet.</div>';
    return;
  }

  const typeIcon = { noyo:'🏗️', rental:'🏢', machine:'🔧' };
  const priColor = { low:'#94A3B8', normal:'#0052CC', urgent:'#EF4444' };
  const priBg    = { low:'#F8FAFC', normal:'#EFF6FF', urgent:'#FEF2F2' };

  let html2 = '';

  // Group rental ratings by company for summary cards
  const rentalRatings = ratings.filter(r => r.type === 'rental');
  const noyoRatings   = ratings.filter(r => r.type === 'noyo');
  const byCompany = {};
  rentalRatings.forEach(r => {
    if (!byCompany[r.company]) byCompany[r.company] = [];
    byCompany[r.company].push(r);
  });

  if (ratings.length > 0) {
    html2 += `<div style="font-size:.75rem;font-weight:800;color:#94A3B8;text-transform:uppercase;letter-spacing:.5px;margin-bottom:.6rem">⭐ Ratings (${ratings.length})</div>`;

    // Rental company summaries
    if (Object.keys(byCompany).length > 0) {
      html2 += `<div style="font-size:.75rem;font-weight:800;color:#64748B;margin-bottom:.4rem">🏢 Rental Company Scores</div>`;
      html2 += Object.entries(byCompany).map(([co, revs]) => {
        const catKeys = ['machine','ontime','comms','value'];
        const catLabels = {machine:'🔧 Machine',ontime:'⏱ On Time',comms:'💬 Comms',value:'💰 Value'};
        const catAvg = key => {
          const s = revs.filter(r => r.categories && r.categories[key] > 0);
          return s.length ? (s.reduce((a,r) => a+r.categories[key], 0) / s.length).toFixed(1) : '—';
        };
        const overallAvg = revs.filter(r=>r.overall>0);
        const overall = overallAvg.length ? (overallAvg.reduce((s,r)=>s+r.overall,0)/overallAvg.length).toFixed(1) : '—';
        return `<div style="background:#FFFBEB;border:1.5px solid #FDE68A;border-radius:12px;padding:.8rem 1rem;margin-bottom:.5rem">
          <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:.4rem;flex-wrap:wrap;gap:.3rem">
            <span style="font-weight:900;font-size:.9rem;color:#92400E">🏢 ${co}</span>
            <span style="font-weight:900;font-size:1rem;color:#B45309">⭐ ${overall} <span style="font-size:.75rem;font-weight:600;color:#92400E">(${revs.length} review${revs.length!==1?'s':''})</span></span>
          </div>
          <div style="display:flex;gap:.5rem;flex-wrap:wrap">
            ${catKeys.map(k => `<span style="background:#FEF9C3;border:1px solid #FDE68A;border-radius:8px;padding:.18rem .55rem;font-size:.75rem;font-weight:700;color:#78350F">${catLabels[k]}: ${catAvg(k)}</span>`).join('')}
          </div>
          ${revs.slice(-3).map(r => r.comment ? `<div style="font-size:.76rem;color:#78350F;font-style:italic;margin-top:.3rem;padding:.3rem .5rem;background:#FEF3C7;border-radius:6px">"${r.comment}" — ${r.userName||r.user}, ${r.date||''}</div>` : '').join('')}
        </div>`;
      }).join('');
    }

    // Noyo ratings
    if (noyoRatings.length > 0) {
      const noyoAvg = noyoRatings.filter(r=>r.stars>0);
      const noyoScore = noyoAvg.length ? (noyoAvg.reduce((s,r)=>s+r.stars,0)/noyoAvg.length).toFixed(1) : '—';
      html2 += `<div style="background:#EFF6FF;border:1.5px solid #BFDBFE;border-radius:12px;padding:.8rem 1rem;margin-bottom:.5rem">
        <div style="display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:.3rem">
          <span style="font-weight:900;font-size:.9rem;color:#1E40AF">🏗️ Noyo Platform Rating</span>
          <span style="font-weight:900;font-size:1rem;color:#1D4ED8">⭐ ${noyoScore} <span style="font-size:.75rem;font-weight:600;color:#1E40AF">(${noyoRatings.length} review${noyoRatings.length!==1?'s':''})</span></span>
        </div>
        ${noyoRatings.slice(-3).filter(r=>r.comment).map(r => `<div style="font-size:.76rem;color:#1E40AF;font-style:italic;margin-top:.3rem;padding:.3rem .5rem;background:#DBEAFE;border-radius:6px">"${r.comment}" — ${r.userName||r.user}, ${r.date||''}</div>`).join('')}
      </div>`;
    }
    html2 += '<div style="height:1rem"></div>';
  }

  if (items.length > 0) {
    html2 += `<div style="font-size:.75rem;font-weight:800;color:#94A3B8;text-transform:uppercase;letter-spacing:.5px;margin-bottom:.5rem">💬 Written Feedback (${items.length})</div>`;
    html2 += items.map((item, idx) => `
      <div style="background:#fff;border:1.5px solid ${item.priority==='urgent'?'#FECACA':item.priority==='low'?'#F1F5F9':'#BFDBFE'};border-radius:12px;padding:.85rem 1rem;margin-bottom:.5rem">
        <div style="display:flex;align-items:flex-start;justify-content:space-between;gap:.5rem;flex-wrap:wrap;margin-bottom:.35rem">
          <div style="display:flex;align-items:center;gap:.4rem">
            <span style="font-size:1rem">${typeIcon[item.type]||'💬'}</span>
            <span style="font-weight:800;font-size:.85rem;color:#0F172A">${item.type==='noyo'?'About Noyo':item.type==='rental'?'About Rental Co':item.type==='machine'?'Machine Data Feedback':'Feedback'}</span>
            ${item.rentalCompany?`<span style="font-size:.75rem;color:#64748B;font-weight:600">— ${item.rentalCompany}</span>`:''}
          </div>
          <div style="display:flex;align-items:center;gap:.4rem">
            <span style="font-size:.72rem;font-weight:800;padding:.15rem .55rem;border-radius:20px;background:${priBg[item.priority]||'#F8FAFC'};color:${priColor[item.priority]||'#64748B'}">${item.priority||'normal'}</span>
            <span style="font-size:.72rem;color:#94A3B8">${item.date||new Date(item.ts).toLocaleDateString('en-AU')}</span>
          </div>
        </div>
        <div style="font-size:.84rem;color:#334155;line-height:1.6;background:#F8FAFC;border-radius:8px;padding:.5rem .7rem">"${item.text}"</div>
        <div style="font-size:.72rem;color:#94A3B8;margin-top:.3rem">From: ${item.userName||'Guest'} (${item.user||'anon'})</div>
      </div>`).join('');
  }

  list.innerHTML = html2;
}

// ── FEEDBACK ─────────────────────────────────────────────────────
let _feedbackType = 'noyo';
let _feedbackPriority = 'normal';

function openFeedbackModal() {
  _feedbackType = 'noyo';
  _feedbackPriority = 'normal';
  const el = document.getElementById('feedback-modal');
  const ta = document.getElementById('feedback-text');
  const rn = document.getElementById('feedback-rental-name');
  if (ta) ta.value = '';
  if (rn) rn.value = '';
  // Reset type buttons
  document.querySelectorAll('#feedback-type-btns button').forEach(b => {
    const active = b.dataset.type === 'noyo';
    b.style.borderColor = active ? '#0052CC' : '#E2E8F0';
    b.style.background  = active ? '#EFF6FF' : '#F8FAFC';
    b.style.color       = active ? '#0052CC' : '#334155';
  });
  // Reset priority buttons
  document.querySelectorAll('#feedback-priority-btns button').forEach(b => {
    const active = b.dataset.pri === 'normal';
    b.style.borderColor = active ? '#0052CC' : '#E2E8F0';
    b.style.background  = active ? '#EFF6FF' : '#F8FAFC';
    b.style.color       = active ? '#0052CC' : '#64748B';
  });
  const rentalRow = document.getElementById('feedback-rental-name-row');
  if (rentalRow) rentalRow.style.display = 'none';
  if (el) el.style.display = 'flex';
}

function setFeedbackType(type, btn) {
  _feedbackType = type;
  document.querySelectorAll('#feedback-type-btns button').forEach(b => {
    const active = b === btn;
    b.style.borderColor = active ? '#7C3AED' : '#E2E8F0';
    b.style.background  = active ? '#F5F3FF' : '#F8FAFC';
    b.style.color       = active ? '#6D28D9' : '#334155';
  });
  const rentalRow = document.getElementById('feedback-rental-name-row');
  if (rentalRow) rentalRow.style.display = type === 'rental' ? 'block' : 'none';
}

function setFeedbackPriority(pri, btn) {
  _feedbackPriority = pri;
  const colors = { low:'#64748B', normal:'#0052CC', urgent:'#EF4444' };
  const bgs    = { low:'#F8FAFC', normal:'#EFF6FF', urgent:'#FEF2F2' };
  document.querySelectorAll('#feedback-priority-btns button').forEach(b => {
    const active = b === btn;
    const p = b.dataset.pri;
    b.style.borderColor = active ? colors[p] : '#E2E8F0';
    b.style.background  = active ? bgs[p]    : '#F8FAFC';
    b.style.color       = active ? colors[p] : '#64748B';
  });
}

function submitFeedback() {
  const text = (document.getElementById('feedback-text')?.value || '').trim();
  if (!text) { showToast('Please write your feedback first', '#F59E0B'); return; }
  const rentalName = document.getElementById('feedback-rental-name')?.value.trim() || '';
  const entry = {
    type: _feedbackType,
    priority: _feedbackPriority,
    text,
    rentalCompany: rentalName || null,
    user: currentUser?.email || 'anonymous',
    userName: currentUser?.name || 'Guest',
    ts: Date.now(),
    date: new Date().toLocaleDateString('en-AU',{day:'2-digit',month:'short',year:'numeric'}),
  };
  // Save to localStorage cache
  const existing = JSON.parse(localStorage.getItem('noyo_feedback') || '[]');
  existing.push(entry);
  localStorage.setItem('noyo_feedback', JSON.stringify(existing));
  // Save to Firestore (persistent, cross-device, visible to admin)
  if (_fbDb) {
    _fbDb.collection('feedback').add({
      ...entry,
      createdAt: firebase.firestore.FieldValue.serverTimestamp()
    }).catch(e => console.warn('Feedback Firestore save failed:', e.message));
  }
  // Close modal
  const el = document.getElementById('feedback-modal');
  if (el) el.style.display = 'none';
  const typeLabel = _feedbackType === 'noyo' ? 'Noyo' : _feedbackType === 'rental' ? (rentalName || 'rental company') : 'machine data';
  showToast(`💬 Feedback about ${typeLabel} received — thank you!`, '#7C3AED');
}


// ── CUMULATIVE RENTAL COMPANY RATINGS ──────────────────────────────
function getRentalCompanyRatings(companyName) {
  const all = JSON.parse(localStorage.getItem('noyo_ratings') || '[]');
  return all.filter(r => r.type === 'rental' && r.company === companyName);
}

function getCompanyRatingSummary(companyName) {
  const reviews = getRentalCompanyRatings(companyName);
  if (reviews.length === 0) return null;
  const avg = r => reviews.filter(x => x.categories && x.categories[r] > 0);
  const catAvg = (key) => {
    const scored = reviews.filter(r => r.categories && r.categories[key] > 0);
    if (!scored.length) return null;
    return Math.round(scored.reduce((s, r) => s + r.categories[key], 0) / scored.length * 10) / 10;
  };
  const overalls = reviews.filter(r => r.overall > 0);
  const overall = overalls.length ? Math.round(overalls.reduce((s, r) => s + r.overall, 0) / overalls.length * 10) / 10 : null;
  return {
    overall,
    count: reviews.length,
    machine: catAvg('machine'),
    ontime:  catAvg('ontime'),
    comms:   catAvg('comms'),
    value:   catAvg('value'),
    reviews,
  };
}

function renderStarBadge(score, count, compact) {
  if (!score) return '';
  const full  = Math.floor(score);
  const half  = score - full >= 0.4;
  const stars = '★'.repeat(full) + (half ? '½' : '') + '☆'.repeat(5 - full - (half?1:0));
  if (compact) {
    return `<span style="display:inline-flex;align-items:center;gap:.25rem;background:#FFFBEB;border:1px solid #FDE68A;border-radius:20px;padding:.15rem .55rem;font-size:.78rem;font-weight:800;color:#B45309" title="${score}/5 from ${count} review${count!==1?'s':''}">
      ⭐ ${score.toFixed(1)} <span style="font-weight:600;color:#92400E;font-size:.72rem">(${count})</span>
    </span>`;
  }
  return `<div style="display:flex;align-items:center;gap:.4rem;flex-wrap:wrap">
    <span style="font-size:1.1rem;color:#F59E0B;letter-spacing:.05rem">${stars}</span>
    <span style="font-weight:800;font-size:.9rem;color:#B45309">${score.toFixed(1)}</span>
    <span style="font-size:.78rem;color:#64748B">${count} review${count!==1?'s':''}</span>
  </div>`;
}

// ── RATINGS ─────────────────────────────────────────────────────
const _noyoRatings = JSON.parse(localStorage.getItem('noyo_ratings') || '[]');

function saveRating(type, reqId, stars, comment) {
  const entry = { type, reqId, stars, comment, ts: Date.now(),
    user: currentUser?.email || 'anon', company: null };
  if (type === 'rental') {
    const req = quoteInbox.find(r => r.id === reqId);
    entry.company = req?.acceptedBy || '—';
  }
  _noyoRatings.push(entry);
  localStorage.setItem('noyo_ratings', JSON.stringify(_noyoRatings));
  // Persist to Firestore
  if (_fbDb) {
    _fbDb.collection('ratings').add({
      ...entry,
      createdAt: firebase.firestore.FieldValue.serverTimestamp()
    }).catch(e => console.warn('Rating Firestore save failed:', e.message));
  }
  // Mark on the request so we don't prompt again
  const req = quoteInbox.find(r => r.id === reqId);
  if (req) {
    if (type === 'noyo')   req._ratedNoyo   = stars;
    if (type === 'rental') req._ratedRental = stars;
    saveInbox(); saveQuoteToFirebase(req);
  }
}

function openRateNoyo(reqId) {
  const req = quoteInbox.find(r => r.id === reqId);
  if (!req) return;
  const content = document.getElementById('rating-modal-content');
  if (!content) return;
  content.innerHTML = `
    <div style="text-align:center;margin-bottom:1rem">
      <div style="font-size:2.5rem;margin-bottom:.4rem">⭐</div>
      <div style="font-weight:900;font-size:1.15rem;color:#0052CC;margin-bottom:.3rem">Rate Noyo</div>
      <div style="font-size:.85rem;color:#64748B;line-height:1.55">How was your experience finding the right machine?<br>Your feedback helps us improve.</div>
    </div>
    <div id="noyo-stars" style="display:flex;justify-content:center;gap:.6rem;margin:1rem 0">
      ${[1,2,3,4,5].map(s=>`<button onclick="selectStar('noyo-stars',${s})" data-star="${s}"
        style="font-size:2rem;background:none;border:none;cursor:pointer;transition:transform .15s;filter:grayscale(1)" >⭐</button>`).join('')}
    </div>
    <textarea id="noyo-rating-comment" placeholder="Optional — any feedback for us?" rows="2"
      style="width:100%;border:1.5px solid #E2E8F0;border-radius:10px;padding:.6rem .8rem;font-size:.85rem;font-family:inherit;resize:none;box-sizing:border-box;margin-bottom:.8rem"></textarea>
    <button onclick="submitRating('noyo','${reqId}')"
      style="width:100%;background:linear-gradient(135deg,#0052CC,#1a6fd4);color:#fff;border:none;border-radius:12px;padding:.75rem;font-family:'Nunito',sans-serif;font-weight:800;font-size:.95rem;cursor:pointer">
      Submit Rating
    </button>`;
  const el = document.getElementById('rating-modal');
  if (el) el.style.display = 'flex';
  _selectedStar['noyo-stars'] = 0;
}

// 4 rating dimensions for rental companies
var RC_RATING_CATS = [
  { id:'machine',   icon:'🔧', label:'Machine Quality',   hint:'Was the machine well-maintained and fit for purpose?' },
  { id:'ontime',    icon:'⏱️', label:'On-Time Delivery',  hint:'Did they deliver and pick up on schedule?' },
  { id:'comms',     icon:'💬', label:'Communication',     hint:'Were they responsive and clear throughout?' },
  { id:'value',     icon:'💰', label:'Value for Money',   hint:'Was the pricing fair for the quality received?' },
];

function openRateRentalCompany(reqId) {
  const req = quoteInbox.find(r => r.id === reqId);
  if (!req) return;
  const company = req.acceptedBy || 'Rental Company';
  const content = document.getElementById('rating-modal-content');
  if (!content) return;

  // Reset category stars
  RC_RATING_CATS.forEach(c => { _selectedStar['rc_' + c.id] = 0; });

  content.innerHTML = `
    <div style="text-align:center;margin-bottom:1rem">
      <div style="font-size:2rem;margin-bottom:.3rem">🏢</div>
      <div style="font-weight:900;font-size:1.1rem;color:#0052CC;margin-bottom:.2rem">Rate ${company}</div>
      <div style="font-size:.82rem;color:#64748B;line-height:1.5">Help other customers by rating your hire experience.</div>
    </div>
    <div style="display:flex;flex-direction:column;gap:.65rem;margin-bottom:.9rem">
      ${RC_RATING_CATS.map(cat => `
        <div style="background:#F8FAFC;border:1.5px solid #E2E8F0;border-radius:10px;padding:.6rem .85rem">
          <div style="display:flex;align-items:center;justify-content:space-between;gap:.5rem;flex-wrap:wrap">
            <div>
              <span style="font-size:.88rem;font-weight:800;color:#0F172A">${cat.icon} ${cat.label}</span>
              <div style="font-size:.73rem;color:#94A3B8;margin-top:.1rem">${cat.hint}</div>
            </div>
            <div id="rc-stars-${cat.id}" style="display:flex;gap:.2rem">
              ${[1,2,3,4,5].map(s=>`<button onclick="selectRcStar('${cat.id}',${s})" data-star="${s}"
                style="font-size:1.4rem;background:none;border:none;cursor:pointer;transition:transform .12s;filter:grayscale(1);padding:.05rem">⭐</button>`).join('')}
            </div>
          </div>
        </div>`).join('')}
    </div>
    <textarea id="rental-rating-comment" placeholder="Any other comments? (optional)" rows="2"
      style="width:100%;border:1.5px solid #E2E8F0;border-radius:10px;padding:.6rem .8rem;font-size:.85rem;font-family:inherit;resize:none;box-sizing:border-box;margin-bottom:.8rem"></textarea>
    <button onclick="submitRentalRating('${reqId}')"
      style="width:100%;background:linear-gradient(135deg,#16A34A,#15803D);color:#fff;border:none;border-radius:12px;padding:.75rem;font-family:'Nunito',sans-serif;font-weight:800;font-size:.95rem;cursor:pointer">
      Submit Rating
    </button>`;
  const el = document.getElementById('rating-modal');
  if (el) el.style.display = 'flex';
}

function selectRcStar(catId, star) {
  _selectedStar['rc_' + catId] = star;
  const btns = document.querySelectorAll(`#rc-stars-${catId} button`);
  btns.forEach(btn => {
    const s = parseInt(btn.dataset.star);
    btn.style.filter = s <= star ? 'grayscale(0)' : 'grayscale(1)';
    btn.style.transform = s === star ? 'scale(1.25)' : 'scale(1)';
  });
}

function submitRentalRating(reqId) {
  const req = quoteInbox.find(r => r.id === reqId);
  if (!req) return;
  // Validate — at least one category must be rated
  const catScores = {};
  let anyRated = false;
  RC_RATING_CATS.forEach(c => {
    const s = _selectedStar['rc_' + c.id] || 0;
    catScores[c.id] = s;
    if (s > 0) anyRated = true;
  });
  if (!anyRated) { showToast('Please rate at least one category', '#F59E0B'); return; }

  // Overall = average of rated categories
  const rated = RC_RATING_CATS.filter(c => catScores[c.id] > 0);
  const overall = Math.round(rated.reduce((s, c) => s + catScores[c.id], 0) / rated.length * 10) / 10;

  const comment = document.getElementById('rental-rating-comment')?.value.trim() || '';
  const company = req.acceptedBy || '—';

  // Save to noyo_ratings with full category breakdown
  const entry = {
    type: 'rental',
    reqId,
    company,
    overall,
    categories: catScores,
    comment,
    ts: Date.now(),
    user: currentUser?.email || 'anon',
    userName: currentUser?.name || 'Customer',
    date: new Date().toLocaleDateString('en-AU', {day:'2-digit',month:'short',year:'numeric'}),
  };
  const existing = JSON.parse(localStorage.getItem('noyo_ratings') || '[]');
  existing.push(entry);
  localStorage.setItem('noyo_ratings', JSON.stringify(existing));
  // Persist to Firestore (permanent, cross-device, admin-visible)
  if (_fbDb) {
    _fbDb.collection('ratings').add({
      ...entry,
      createdAt: firebase.firestore.FieldValue.serverTimestamp()
    }).catch(e => console.warn('Rental rating Firestore save failed:', e.message));
  }

  // Mark request as rated
  req._ratedRental = overall;
  req._ratedRentalCats = catScores;
  saveInbox(); saveQuoteToFirebase(req);

  const el = document.getElementById('rating-modal');
  if (el) el.style.display = 'none';
  const starStr = overall >= 4.5 ? '⭐⭐⭐⭐⭐' : overall >= 3.5 ? '⭐⭐⭐⭐' : overall >= 2.5 ? '⭐⭐⭐' : '⭐⭐';
  showToast(`${starStr} Thank you for rating ${company}!`, '#16A34A');
  renderMyQuotes();
}

const _selectedStar = {};
const _selectedTags = {};

function selectStar(groupId, star) {
  _selectedStar[groupId] = star;
  const btns = document.querySelectorAll(`#${groupId} button`);
  btns.forEach(btn => {
    const s = parseInt(btn.dataset.star);
    btn.style.filter = s <= star ? 'grayscale(0)' : 'grayscale(1)';
    btn.style.transform = s <= star ? 'scale(1.2)' : 'scale(1)';
  });
}

function toggleRatingTag(el, tag) {
  if (!_selectedTags['rental']) _selectedTags['rental'] = new Set();
  if (_selectedTags['rental'].has(tag)) {
    _selectedTags['rental'].delete(tag);
    el.style.background = '#F1F5F9';
    el.style.borderColor = '#E2E8F0';
    el.style.color = '#334155';
  } else {
    _selectedTags['rental'].add(tag);
    el.style.background = '#DCFCE7';
    el.style.borderColor = '#86EFAC';
    el.style.color = '#166534';
  }
}

function submitRating(type, reqId) {
  const groupId = type === 'noyo' ? 'noyo-stars' : 'rental-stars';
  const stars = _selectedStar[groupId] || 0;
  if (stars === 0) {
    showToast('Please select a star rating first', '#F59E0B'); return;
  }
  const commentEl = document.getElementById(type === 'noyo' ? 'noyo-rating-comment' : 'rental-rating-comment');
  let comment = commentEl ? commentEl.value.trim() : '';
  if (type === 'rental' && _selectedTags['rental'] && _selectedTags['rental'].size > 0) {
    const tags = [..._selectedTags['rental']].join(', ');
    comment = comment ? `${tags}. ${comment}` : tags;
    _selectedTags['rental'] = new Set();
  }
  saveRating(type, reqId, stars, comment);
  const el = document.getElementById('rating-modal');
  if (el) el.style.display = 'none';
  const starStr = '⭐'.repeat(stars);
  if (type === 'noyo') {
    showToast(`${starStr} Thank you for rating Noyo!`, '#0052CC');
  } else {
    const req = quoteInbox.find(r => r.id === reqId);
    showToast(`${starStr} Thank you for rating ${req?.acceptedBy || 'the rental company'}!`, '#16A34A');
  }
  renderMyQuotes();
}
